"use client";

import { forwardRef } from "react";
import { cn } from "@/lib/utils";
import type { GanttTimelineHandle, GanttTimelineProps } from "./types";
import { GanttTimelineRoot } from "./parts/gantt-timeline-root";
import { GanttTimelineToolbar } from "./parts/gantt-timeline-toolbar";
import { GanttTimelineAxis } from "./parts/gantt-timeline-axis";
import { GanttTimelineGutter } from "./parts/gantt-timeline-gutter";
import { GanttTimelineBody } from "./parts/gantt-timeline-body";

/**
 * Tier A — batteries-included assembly. `Root` + the parts gated by `showToolbar`.
 * Contains no logic the parts don't; a hand-assembly (Root + any subset of parts)
 * gets identical behavior.
 */
export const GanttTimeline01 = forwardRef<
  GanttTimelineHandle,
  GanttTimelineProps
>(function GanttTimeline01(props, ref) {
  const { showToolbar = true, className, data, ...rest } = props;

  if (!data || data.length === 0) {
    return (
      <div
        className={cn(
          "flex h-80 flex-col items-center justify-center gap-2 rounded-lg border border-border bg-card px-6 text-center",
          className,
        )}
      >
        <p className="text-sm font-medium text-foreground">No tasks to schedule</p>
        <p className="text-xs text-muted-foreground">
          Pass a <code className="font-mono">TodoItem[]</code> to{" "}
          <code className="font-mono">data</code> to render the timeline.
        </p>
      </div>
    );
  }

  return (
    <GanttTimelineRoot
      ref={ref}
      data={data}
      {...rest}
      className={cn(
        "overflow-hidden rounded-lg border border-border bg-card",
        className,
      )}
    >
      {showToolbar ? <GanttTimelineToolbar /> : null}
      <GanttTimelineAxis />
      <div className="flex h-[clamp(280px,52vh,560px)]">
        <GanttTimelineGutter />
        <GanttTimelineBody />
      </div>
    </GanttTimelineRoot>
  );
});

// Assembly (Tier A)
export { GanttTimeline01 } from "./gantt-timeline-01";

// Headless provider + context parts (Tier B) — flat exports, never a namespace
export { GanttTimelineRoot } from "./parts/gantt-timeline-root";
export { GanttTimelineToolbar } from "./parts/gantt-timeline-toolbar";
export { GanttTimelineAxis } from "./parts/gantt-timeline-axis";
export { GanttTimelineGutter } from "./parts/gantt-timeline-gutter";
export { GanttTimelineBody } from "./parts/gantt-timeline-body";

// Standalone primitives (Tier C)
export {
  GanttBar,
  SummaryBar,
  MilestoneDiamond,
  TodayLine,
  BarTooltip,
} from "./parts/gantt-bars";
export { AxisHeader } from "./parts/gantt-timeline-axis";
export { GutterRow } from "./parts/gantt-timeline-gutter";
export { GanttTimelineSkeleton } from "./parts/gantt-timeline-skeleton";
export { GanttFullCardTooltip } from "./parts/bar-tooltip-full";

// Editing (v0.2.0)
export { GanttContextMenu } from "./parts/gantt-context-menu";
export { GanttEditPopover } from "./parts/gantt-edit-popover";
// Quick-create composer (v0.5.0)
export { GanttQuickComposer } from "./parts/gantt-quick-composer";

// Hook
export { useGanttTimeline } from "./hooks/use-gantt-context";

// Public types (+ the consumed todo-rich-card data language, re-exported)
export type {
  GanttTimelineProps,
  GanttTimelineRootProps,
  GanttTimelineHandle,
  GanttZoom,
  GanttTimeUnit,
  GanttViewport,
  GanttRow,
  GanttBarGeometry,
  GanttBarColor,
  GanttColorResolver,
  GanttTooltipRenderer,
  GanttStatusTone,
  GanttSnap,
  GanttEditAction,
  GanttComposerTarget,
  GanttQuickComposerRenderer,
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "./types";

/**
 * Public + internal types for the gantt-timeline-01 pro-component.
 *
 * v0.1.0 surface — read-only, fully-navigable project timeline over the
 * canonical `TodoItem[]`. Bars from effective start→end, WBS summary rows from
 * `children`, milestone diamonds, continuous-zoom two-tier axis, pan/swipe/zoom
 * canvas, filled status/urgency bars (ramp imported from todo-rich-card).
 *
 * Architecture: shadcn-style compound (Root provider + flat parts + Tier-C
 * primitives + assembly). State model architected so v2 drag-to-reschedule
 * drops in additively. See docs/procomps/gantt-timeline-01-procomp/.
 */

import type { ReactNode, RefObject } from "react";
import type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
} from "../todo-rich-card";

// Re-export the consumed data + editing language (v0.2.0) so a consumer importing
// the gantt gets the item, option, permission, and event types without a second
// import (same-category barrel import; rewriter-safe).
export type {
  TodoItem,
  TodoPerson,
  TodoStatusOption,
  TodoPriorityOption,
  TodoLabelOption,
  TodoColorRamp,
  TodoPermissions,
  TodoPermissionRule,
  TodoPermissionReason,
  TodoItemAddedEvent,
  TodoItemRemovedEvent,
  TodoItemMovedEvent,
  TodoFieldEditedEvent,
  TodoStatusChangedEvent,
};

/* ───────── zoom + time ───────── */

export type GanttZoom = "hour" | "day" | "week" | "month" | "quarter";

export type GanttTimeUnit =
  | "hour"
  | "day"
  | "week"
  | "month"
  | "quarter"
  | "year";

/** Linear map epoch-ms → x-pixels: `x(t) = (t - originMs) * pxPerMs`. */
export type GanttViewport = { originMs: number; pxPerMs: number };

export type GanttStatusTone = "active" | "done" | "blocked";

/* ───────── editing (v0.2.0) ───────── */

/** Snap granularity for drag / resize / create; default `"minor"` (active axis unit). */
export type GanttSnap = "minor" | "hour" | "day" | "week" | "off" | number;

/** The edit actions the permission matrix gates. */
export type GanttEditAction =
  | "move"
  | "resize"
  | "delete"
  | "create"
  | "editDetails";

/**
 * v0.5.0 — a pending quick-create. Set when a double-click on an empty row area
 * requests a new task; the composer floats at (x,y) until commit/cancel.
 */
export type GanttComposerTarget = {
  /** Anchor start (epoch-ms) for the new task. */
  startMs: number;
  /** Default end (epoch-ms); the composer seeds `expireAt` from it. */
  endMs?: number;
  /** Insert under this parent (null = root). */
  parentId: string | null;
  /** Insert index among siblings. */
  index: number;
  /** Pointer anchor for the floating panel. */
  x?: number;
  y?: number;
};

/** v0.5.0 — override the quick-composer UI (parity with calendar). */
export type GanttQuickComposerRenderer = (args: {
  startMs: number;
  endMs?: number;
  commit: (seed?: Partial<TodoItem>) => void;
  cancel: () => void;
  openFull: () => void;
}) => ReactNode;

/* ───────── derived row + geometry ───────── */

/** A flattened, currently-visible row (respects collapse). */
export type GanttRow = {
  item: TodoItem;
  /** 0 = top-level. */
  depth: number;
  parentId: string | null;
  hasChildren: boolean;
  /** A parent renders a summary bar. */
  isSummary: boolean;
  collapsed: boolean;
  /** 1-based position among same-parent siblings (for `aria-posinset`). */
  posInSet: number;
  /** Sibling count under the same parent (for `aria-setsize`). */
  setSize: number;
};

/** Resolved bar geometry for one item. `endMs === null` ⇒ milestone. */
export type GanttBarGeometry = {
  startMs: number;
  endMs: number | null;
  isMilestone: boolean;
  isOverdue: boolean;
};

/** Resolved fill for a bar. */
export type GanttBarColor = {
  fill: string;
  tone: GanttStatusTone;
  isOverdue: boolean;
};

export type GanttColorResolver = (item: TodoItem) => GanttBarColor;

export type GanttTooltipRenderer = (item: TodoItem) => ReactNode;

/* ───────── component props ───────── */

export type GanttTimelineProps = {
  /** The tasks to lay out. The canonical `TodoItem[]` the card/tree render. */
  data: TodoItem[];

  // Color + label language (shared with todo-rich-card)
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];
  /** Same urgency ramp the card uses; default `"default"`. */
  colorRamp?: TodoColorRamp;
  /** ms; default 60_000; 0 disables the refresh tick. */
  colorRefreshIntervalMs?: number;

  // Time axis (continuous zoom; named levels are header-scale buckets)
  zoom?: GanttZoom; // controlled (nearest named level)
  defaultZoom?: GanttZoom; // uncontrolled (default "week")
  onZoomChange?: (zoom: GanttZoom) => void;
  /** Clamp the continuous zoom; default span hour…quarter. */
  minZoom?: GanttZoom;
  maxZoom?: GanttZoom;
  /** Fires (rAF-throttled) when the viewport pans/zooms. */
  onViewportChange?: (window: { from: string; to: string }) => void;
  /** Opt out of gesture nav; +/−/fit buttons + keyboard still work. */
  disableGestures?: boolean;
  /** Initial visible window; defaults to fit-all-bars + padding. */
  range?: { from: string; to: string };
  /** Frozen clock for SSR/testing; drives the "now" line + urgency. */
  now?: Date | (() => Date);

  // Layout
  rowHeight?: number; // px; default 36
  gutterWidth?: number; // px; default 280
  showWeekendShading?: boolean; // default false
  showToolbar?: boolean; // assembly toggle; default true

  // Collapse (UI-only)
  defaultCollapsedIds?: string[];
  collapsedIds?: string[]; // controlled
  onCollapsedChange?: (ids: string[]) => void;

  // Read-only interactions
  selectedId?: string | null;
  onSelect?: (itemId: string | null) => void;
  onTaskClick?: (item: TodoItem) => void;
  /** Override the hover tooltip; default = lightweight summary. */
  renderTooltip?: GanttTooltipRenderer;

  // ── Editing (v0.2.0) — all opt-in; default surface is the v1 read-only Gantt ──
  /** Master switch. Default false → byte-identical v1 read-only behavior. */
  editable?: boolean;
  /** The full mutated forest after ANY edit; controlled consumer echoes into `data`. */
  onChange?: (data: TodoItem[]) => void;
  /** Snap granularity for drags/resizes/create; default "minor"; Alt = free-drag. */
  snap?: GanttSnap;

  /**
   * v0.5.0 — when true (default while editable), double-clicking an empty row area
   * opens a quick mini-composer; false → creates immediately + opens the full editor.
   */
  quickCompose?: boolean;
  /** v0.5.0 — override the quick-composer UI. */
  renderQuickComposer?: GanttQuickComposerRenderer;

  /** Bar move/resize sugar — kept from v1; fires alongside onChange/onFieldEdited. */
  onTaskReschedule?: (next: {
    itemId: string;
    startAt: string;
    expireAt?: string;
  }) => void;

  // CRUD + field events (shapes reused from todo-rich-card)
  onItemAdded?: (event: TodoItemAddedEvent) => void;
  onItemRemoved?: (event: TodoItemRemovedEvent) => void;
  onItemMoved?: (event: TodoItemMovedEvent) => void;
  onFieldEdited?: (event: TodoFieldEditedEvent) => void;
  onStatusChanged?: (event: TodoStatusChangedEvent) => void;

  // Permissions (reused from todo-rich-card; mirrors todo-tree)
  permissions?: TodoPermissions;
  canMoveItem?: (id: string) => boolean;
  canResizeItem?: (id: string) => boolean;
  canDeleteItem?: (id: string) => boolean;
  canCreateChild?: (id: string) => boolean;
  canEditItem?: (id: string) => boolean;
  onPermissionDenied?: (
    action: keyof TodoPermissionRule,
    itemId: string,
    reason: TodoPermissionReason,
  ) => void;

  className?: string;
  "aria-label"?: string;
};

/** Headless provider props = assembly props minus the assembly-only toggle. */
export type GanttTimelineRootProps = Omit<GanttTimelineProps, "showToolbar"> & {
  children: ReactNode;
};

/* ───────── imperative handle ───────── */

export type GanttTimelineHandle = {
  scrollToDate(date: string): void;
  scrollToItem(itemId: string): void;
  scrollToToday(): void;
  expandAll(): void;
  collapseAll(): void;
  setZoom(zoom: GanttZoom): void;
  /** Multiply the continuous zoom (focal = viewport center). */
  zoomBy(factor: number): void;
  /** Frame all bars + padding. */
  zoomToFit(): void;

  // Editing (v0.2.0) — no-ops when `editable` is false / permission denied.
  /** Create a task under `parentId` (null = root); a partial seeds the rest. */
  addTask(parentId: string | null, item?: Partial<TodoItem>): void;
  deleteTask(itemId: string): void;
  /** Open the detail editor (embedded card) for an item. */
  editTask(itemId: string): void;
  /** Start inline rename of a gutter row. */
  beginRename(itemId: string): void;
  /**
   * v0.3.0 — group-move a summary's whole subtree by `deltaMs` (signed epoch-ms).
   * No-op unless `editable` and the group is movable (summary + every leaf).
   */
  shiftTaskGroup(summaryId: string, deltaMs: number): void;
};

/* ───────── context (internal; constructed in the Root) ───────── */

/** One render slot — either a virtualizer item or a plain row offset. */
export type GanttRenderItem = { index: number; start: number };

export type GanttContextValue = {
  // data + rows
  rows: GanttRow[];
  renderItems: GanttRenderItem[];
  totalSize: number;
  rowHeight: number;
  gutterWidth: number;

  // scroll refs / vertical sync
  bodyScrollRef: RefObject<HTMLDivElement | null>;
  gutterTrackRef: RefObject<HTMLDivElement | null>;
  onBodyScroll: (scrollTop: number) => void;
  measureRows: () => void;

  // viewport + scale
  viewport: GanttViewport;
  bodyWidth: number;
  setBodyWidth: (w: number) => void;
  dataExtent: { startMs: number; endMs: number };

  // gestures
  disableGestures: boolean;
  onPan: (deltaPx: number) => void;
  onZoomAt: (factor: number, focalPx: number) => void;
  beginPan: () => void;
  endPanWithVelocity: (velocityPxPerMs: number) => void;

  // zoom helpers / named
  namedZoom: GanttZoom;
  setZoomLevel: (z: GanttZoom) => void;
  zoomBy: (factor: number) => void;
  zoomToFit: () => void;
  scrollToToday: () => void;
  scrollToItemId: (id: string) => void;
  pageBy: (dir: -1 | 1) => void;

  // color + time + geometry
  nowMs: number;
  showTodayLine: boolean;
  resolveColor: GanttColorResolver;
  geometryFor: (item: TodoItem) => GanttBarGeometry;
  summarySpanFor: (item: TodoItem) => { startMs: number; endMs: number } | null;

  // display config
  statusOptions?: TodoStatusOption[];
  priorityOptions?: TodoPriorityOption[];
  labelOptions?: TodoLabelOption[];
  showWeekendShading: boolean;

  // collapse + selection + focus
  isCollapsed: (id: string) => boolean;
  toggleCollapse: (id: string) => void;
  selectedId: string | null;
  select: (id: string | null) => void;
  onTaskClick?: (item: TodoItem) => void;
  renderTooltip?: GanttTooltipRenderer;
  focusedId: string | null;
  setFocusedId: (id: string | null) => void;

  // ── editing (v0.2.0) — always present; dispatchers are no-ops when !editable ──
  editable: boolean;
  snap: GanttSnap;
  /**
   * v0.4.0 — draw mode. When true, dragging a task row's empty area draws a new
   * bar; when false (default) that drag pans the dates. Toolbar-toggled; only
   * meaningful while `editable`.
   */
  drawMode: boolean;
  setDrawMode: (on: boolean) => void;
  /** The raw permission matrix (threaded into the embedded edit card). */
  permissions?: TodoPermissions;
  /** Look up any item in the forest by id (incl. collapsed). */
  getItem: (id: string) => TodoItem | undefined;
  /** Effective permission for an action on an item (matrix + can* predicate + locked). */
  can: (action: GanttEditAction, item: TodoItem) => boolean;
  /**
   * v0.3.0 — can this summary's whole subtree be group-moved? Atomic: the summary
   * must be movable AND every descendant leaf must pass `can("move")`. Drives both
   * the bracket-drag gate and the grab cursor.
   */
  canGroupMove: (item: TodoItem) => boolean;
  /** parentId / index / level lookup over the current forest. */
  nodeInfo: (
    id: string,
  ) => { parentId: string | null; index: number; level: number } | undefined;

  // mutation dispatchers — compute the next forest, fire the typed event + onChange
  rescheduleItem: (
    id: string,
    patch: { startAt?: string; expireAt?: string; duration?: number },
    kind: "move" | "resize",
  ) => void;
  createItem: (
    parentId: string | null,
    seed?: Partial<TodoItem>,
    index?: number,
    opts?: { openEditor?: boolean },
  ) => void;
  deleteItem: (id: string) => void;
  renameItemAction: (id: string, name: string) => void;
  moveItemAction: (
    id: string,
    newParentId: string | null,
    newIndex: number,
  ) => void;
  /** v0.3.0 — group-move: shift a summary's whole subtree by `deltaMs` (atomic-gated). */
  moveSubtree: (id: string, deltaMs: number) => void;
  changeStatus: (id: string, status: string) => void;
  /** v0.5.0 — set priority (mutate + onChange only; "priority" is not a typed field). */
  changePriority: (id: string, priority: string) => void;

  // detail editor (popover) target
  editingId: string | null;
  openEditor: (id: string) => void;
  closeEditor: () => void;
  /** Splice an edited subtree (same root id) back into the forest. */
  applyEditedSubtree: (next: TodoItem) => void;

  // inline rename (gutter) target
  renamingId: string | null;
  beginRename: (id: string) => void;
  endRename: () => void;

  // ── quick-create composer (v0.5.0) ──
  quickCompose: boolean;
  renderQuickComposer?: GanttQuickComposerRenderer;
  composerTarget: GanttComposerTarget | null;
  openComposer: (target: GanttComposerTarget) => void;
  closeComposer: () => void;

  // ── cross-surface clipboard (v0.5.0) — copy/cut programmatic; paste from a parsed envelope ──
  /** Copy an item's subtree to the OS clipboard (shared `ilinxa/task` envelope). */
  copyItem: (id: string) => void;
  /** Copy then delete (gated on delete). */
  cutItem: (id: string) => void;
  /** Insert pasted tasks (re-id'd) under `parentId` at `index` (append if omitted). */
  pasteTasks: (
    items: TodoItem[],
    parentId: string | null,
    index?: number,
  ) => void;
};

/**
 * Bar color resolution. The OKLCH urgency ramp is IMPORTED from todo-rich-card
 * (`RAMPS`) — not re-derived — so the timeline matches the card exactly. Only
 * the done/blocked tones are adapted to filled bars (gray / red), per the
 * procomp description §9.
 *
 * `RAMPS` must be the FIRST `from`-import so the meta-deps audit registers the
 * todo-rich-card dependency (blackboard-01 / content-composer-01 lesson).
 */

import { RAMPS } from "../../todo-rich-card";
import type {
  GanttStatusTone,
  TodoColorRamp,
  TodoItem,
  TodoStatusOption,
} from "../types";
import { effEndMs, effStartMs } from "./geometry";

export function toneFor(
  item: TodoItem,
  statusOptions?: TodoStatusOption[],
): GanttStatusTone {
  const opt = statusOptions?.find((o) => o.value === item.status);
  return opt?.tone ?? "active";
}

/** Resolve a `TodoColorRamp` (preset name | custom fn) into a callable. */
export function resolveRamp(
  ramp: TodoColorRamp | undefined,
): (t: number) => string {
  if (ramp == null) return RAMPS.default;
  if (typeof ramp === "function") return ramp;
  return RAMPS[ramp] ?? RAMPS.default;
}

/** Fraction 0..1 of the item's window that has elapsed at `nowMs`. */
export function elapsedFraction(item: TodoItem, nowMs: number): number {
  const s = effStartMs(item);
  const e = effEndMs(item);
  if (e == null || e <= s) return 0;
  const f = (nowMs - s) / (e - s);
  return f < 0 ? 0 : f > 1 ? 1 : f;
}

/**
 * Final fill for a bar:
 *   borderColor override  → that color (skips the engine)
 *   tone "done"           → gray
 *   tone "blocked"        → red
 *   tone "active"         → time-urgency ramp (green → red)
 */
export function barFill(
  item: TodoItem,
  nowMs: number,
  ramp: (t: number) => string,
  statusOptions?: TodoStatusOption[],
): { fill: string; tone: GanttStatusTone } {
  const tone = toneFor(item, statusOptions);
  if (item.borderColor) return { fill: item.borderColor, tone };
  if (tone === "done") return { fill: "var(--muted-foreground)", tone };
  if (tone === "blocked") return { fill: "var(--destructive)", tone };
  return { fill: ramp(elapsedFraction(item, nowMs)), tone };
}

/**
 * Tree → visible rows (depth-first; skips descendants of collapsed nodes).
 * The gutter + body consume the SAME row array so they stay vertically aligned.
 * Pure; framework-free.
 */

import type { GanttRow, TodoItem } from "../types";

export function flatten(
  data: TodoItem[],
  isCollapsed: (id: string) => boolean,
): GanttRow[] {
  const out: GanttRow[] = [];
  const walk = (
    item: TodoItem,
    depth: number,
    parentId: string | null,
    posInSet: number,
    setSize: number,
  ) => {
    const hasChildren = !!item.children && item.children.length > 0;
    const collapsed = hasChildren && isCollapsed(item.id);
    out.push({
      item,
      depth,
      parentId,
      hasChildren,
      isSummary: hasChildren,
      collapsed,
      posInSet,
      setSize,
    });
    if (hasChildren && !collapsed) {
      const kids = item.children!;
      kids.forEach((child, i) =>
        walk(child, depth + 1, item.id, i + 1, kids.length),
      );
    }
  };
  data.forEach((item, i) => walk(item, 0, null, i + 1, data.length));
  return out;
}

/** Flat id → item index over the whole forest (for scrollToItem etc.). */
export function indexById(data: TodoItem[]): Map<string, TodoItem> {
  const map = new Map<string, TodoItem>();
  const walk = (item: TodoItem) => {
    map.set(item.id, item);
    item.children?.forEach(walk);
  };
  data.forEach(walk);
  return map;
}

/** All ancestor ids that must be expanded for `id` to be visible. */
export function ancestorsOf(data: TodoItem[], id: string): string[] {
  const path: string[] = [];
  const found = { hit: false };
  const walk = (item: TodoItem, trail: string[]) => {
    if (found.hit) return;
    if (item.id === id) {
      found.hit = true;
      path.push(...trail);
      return;
    }
    item.children?.forEach((c) => walk(c, [...trail, item.id]));
  };
  data.forEach((d) => walk(d, []));
  return path;
}

/** Every id that has children (for expandAll/collapseAll). */
export function parentIds(data: TodoItem[]): string[] {
  const ids: string[] = [];
  const walk = (item: TodoItem) => {
    if (item.children && item.children.length > 0) {
      ids.push(item.id);
      item.children.forEach(walk);
    }
  };
  data.forEach(walk);
  return ids;
}

/**
 * Effective-window + hierarchy math. Pure; framework-free.
 *
 * Deterministic resolution (locked in the procomp description §4):
 *   effectiveStart = startAt ?? setAt
 *   effectiveEnd   = expireAt ?? (duration != null ? start + duration : null)
 *   isMilestone    = effectiveEnd == null      → diamond at effectiveStart
 *   isOverdue      = end != null && end < now && tone !== "done"
 */

import type { GanttBarGeometry, GanttStatusTone, TodoItem } from "../types";

export function effStartMs(item: TodoItem): number {
  return Date.parse(item.startAt ?? item.setAt);
}

export function effEndMs(item: TodoItem): number | null {
  if (item.expireAt) return Date.parse(item.expireAt);
  if (item.duration != null) return effStartMs(item) + item.duration;
  return null;
}

export function geometryFor(
  item: TodoItem,
  nowMs: number,
  tone: GanttStatusTone,
): GanttBarGeometry {
  const startMs = effStartMs(item);
  const endMs = effEndMs(item);
  const isMilestone = endMs == null;
  const isOverdue = endMs != null && endMs < nowMs && tone !== "done";
  return { startMs, endMs, isMilestone, isOverdue };
}

/**
 * Summary span for a parent = min(descendant starts) → max(descendant ends),
 * treating a milestone descendant as a point. Returns null for a leaf.
 */
export function summarySpan(
  item: TodoItem,
): { startMs: number; endMs: number } | null {
  if (!item.children || item.children.length === 0) return null;
  let start = Infinity;
  let end = -Infinity;
  const walk = (n: TodoItem) => {
    const s = effStartMs(n);
    const e = effEndMs(n) ?? s; // milestone → point
    if (s < start) start = s;
    if (e > end) end = e;
    n.children?.forEach(walk);
  };
  item.children.forEach(walk);
  if (start === Infinity) return null;
  return { startMs: start, endMs: end };
}

/** Min start / max end across the whole forest (milestones as points). */
export function dataExtent(data: TodoItem[]): { startMs: number; endMs: number } {
  let start = Infinity;
  let end = -Infinity;
  const walk = (n: TodoItem) => {
    const s = effStartMs(n);
    const e = effEndMs(n) ?? s;
    if (Number.isFinite(s) && s < start) start = s;
    if (Number.isFinite(e) && e > end) end = e;
    n.children?.forEach(walk);
  };
  data.forEach(walk);
  if (start === Infinity || end === -Infinity) {
    // Empty / unparseable — a neutral one-month window keeps the axis sane.
    const base = 0;
    return { startMs: base, endMs: base + 30 * 86_400_000 };
  }
  if (start === end) {
    // Single instant — pad to a day so a bar/diamond has room.
    return { startMs: start - 43_200_000, endMs: end + 43_200_000 };
  }
  return { startMs: start, endMs: end };
}

/**
 * Continuous time scale: a linear map epoch-ms ↔ x-pixels, plus the two-tier
 * header scale selection (with a wide hysteresis band) and calendar-aware tick
 * generation. Pure; framework-free. No date library — epoch-ms + `Intl`.
 */

import type { GanttTimeUnit, GanttViewport, GanttZoom } from "../types";

export const MS = {
  minute: 60_000,
  hour: 3_600_000,
  day: 86_400_000,
  week: 604_800_000,
} as const;

/** Approximate unit lengths — used ONLY for scale anchoring, never for labels. */
const APPROX_MS: Record<GanttTimeUnit, number> = {
  hour: MS.hour,
  day: MS.day,
  week: MS.week,
  month: 2_629_800_000, // 30.44 d
  quarter: 7_889_400_000,
  year: 31_557_600_000,
};

export function x(vp: GanttViewport, t: number): number {
  return (t - vp.originMs) * vp.pxPerMs;
}

export function timeAt(vp: GanttViewport, px: number): number {
  return vp.originMs + px / vp.pxPerMs;
}

/* ───────── named-level anchors ───────── */

/** The minor (cell) unit each named zoom level targets. */
const ZOOM_MINOR: Record<GanttZoom, GanttTimeUnit> = {
  hour: "hour",
  day: "day",
  week: "day",
  month: "week",
  quarter: "month",
};

/** A named-zoom level renders its minor cell about this wide. */
const ANCHOR_CELL_PX = 56;

export function pxPerMsForZoom(zoom: GanttZoom): number {
  return ANCHOR_CELL_PX / APPROX_MS[ZOOM_MINOR[zoom]];
}

/** Nearest named level for a given pxPerMs (for the controlled `zoom` echo). */
export function zoomForPxPerMs(pxPerMs: number): GanttZoom {
  const levels: GanttZoom[] = ["hour", "day", "week", "month", "quarter"];
  let best: GanttZoom = "week";
  let bestDist = Infinity;
  for (const lvl of levels) {
    const d = Math.abs(Math.log(pxPerMsForZoom(lvl) / pxPerMs));
    if (d < bestDist) {
      bestDist = d;
      best = lvl;
    }
  }
  return best;
}

/* ───────── two-tier scale selection ───────── */

const SCALE_LADDER: { minor: GanttTimeUnit; major: GanttTimeUnit }[] = [
  { minor: "hour", major: "day" },
  { minor: "day", major: "week" },
  { minor: "day", major: "month" },
  { minor: "week", major: "month" },
  { minor: "month", major: "quarter" },
  { minor: "month", major: "year" },
  { minor: "quarter", major: "year" },
];

// One cutoff over a multiplicatively-spaced ladder: each rung's minor unit is
// ~3–7× the previous, so a single MIN_CELL_PX threshold yields wide, stable
// pxPerMs bands per level and the header doesn't thrash near a boundary. (Band
// stability comes from the rung spacing — not state-dependent hysteresis.)
const MIN_CELL_PX = 40;

/** Pick the finest ladder entry whose minor cell renders ≥ MIN_CELL_PX. */
export function pickScales(pxPerMs: number): {
  minor: GanttTimeUnit;
  major: GanttTimeUnit;
} {
  for (const entry of SCALE_LADDER) {
    if (APPROX_MS[entry.minor] * pxPerMs >= MIN_CELL_PX) return entry;
  }
  return SCALE_LADDER[SCALE_LADDER.length - 1];
}

/* ───────── calendar boundaries (local time, single display tz) ───────── */

export function startOfUnit(unit: GanttTimeUnit, ms: number): number {
  const d = new Date(ms);
  switch (unit) {
    case "hour":
      d.setMinutes(0, 0, 0);
      return d.getTime();
    case "day":
      d.setHours(0, 0, 0, 0);
      return d.getTime();
    case "week": {
      d.setHours(0, 0, 0, 0);
      const monday = (d.getDay() + 6) % 7; // Monday = 0
      d.setDate(d.getDate() - monday);
      return d.getTime();
    }
    case "month":
      d.setHours(0, 0, 0, 0);
      d.setDate(1);
      return d.getTime();
    case "quarter":
      d.setHours(0, 0, 0, 0);
      d.setDate(1);
      d.setMonth(Math.floor(d.getMonth() / 3) * 3);
      return d.getTime();
    case "year":
      d.setHours(0, 0, 0, 0);
      d.setMonth(0, 1);
      return d.getTime();
  }
}

export function addUnit(unit: GanttTimeUnit, ms: number, n = 1): number {
  const d = new Date(ms);
  switch (unit) {
    case "hour":
      d.setHours(d.getHours() + n);
      break;
    case "day":
      d.setDate(d.getDate() + n);
      break;
    case "week":
      d.setDate(d.getDate() + 7 * n);
      break;
    case "month":
      d.setMonth(d.getMonth() + n);
      break;
    case "quarter":
      d.setMonth(d.getMonth() + 3 * n);
      break;
    case "year":
      d.setFullYear(d.getFullYear() + n);
      break;
  }
  return d.getTime();
}

/** Aligned cell-boundary timestamps within [fromMs, toMs], capped for safety. */
export function ticks(
  unit: GanttTimeUnit,
  fromMs: number,
  toMs: number,
  cap = 800,
): number[] {
  const out: number[] = [];
  let t = startOfUnit(unit, fromMs);
  let guard = 0;
  while (t <= toMs && guard < cap) {
    out.push(t);
    t = addUnit(unit, t);
    guard += 1;
  }
  return out;
}

/* ───────── labels ───────── */

function fmt(ms: number, opts: Intl.DateTimeFormatOptions): string {
  return new Intl.DateTimeFormat(undefined, opts).format(new Date(ms));
}

export function minorLabel(unit: GanttTimeUnit, ms: number): string {
  switch (unit) {
    case "hour":
      return fmt(ms, { hour: "2-digit", minute: "2-digit" });
    case "day":
      return fmt(ms, { day: "numeric" });
    case "week":
      return fmt(ms, { month: "short", day: "numeric" });
    case "month":
      return fmt(ms, { month: "short" });
    case "quarter":
      return `Q${Math.floor(new Date(ms).getMonth() / 3) + 1}`;
    case "year":
      return fmt(ms, { year: "numeric" });
  }
}

export function majorLabel(unit: GanttTimeUnit, ms: number): string {
  switch (unit) {
    case "hour":
      return fmt(ms, { weekday: "short", month: "short", day: "numeric" });
    case "day":
      return fmt(ms, { month: "short", day: "numeric" });
    case "week":
      return fmt(ms, { month: "long", year: "numeric" });
    case "month":
      return fmt(ms, { month: "long", year: "numeric" });
    case "quarter":
      return `Q${Math.floor(new Date(ms).getMonth() / 3) + 1} ${new Date(ms).getFullYear()}`;
    case "year":
      return fmt(ms, { year: "numeric" });
  }
}

/** Is this timestamp inside a Sat/Sun day? (for weekend shading) */
export function isWeekend(ms: number): boolean {
  const day = new Date(ms).getDay();
  return day === 0 || day === 6;
}

/**
 * Pure forest mutations over `TodoItem[]` — the editing layer (v0.2.0).
 *
 * The array analogue of todo-rich-card's reducer mutations: every function
 * returns a NEW forest with structural sharing and NEVER mutates in place, so
 * the controlled consumer can diff/echo and stack undo for free. Framework-free;
 * Vitest-ready. Hierarchy is nested `children` (no parentId on TodoItem), so the
 * index here is what callers use to locate a splice point.
 */

import type { TodoItem } from "../types";
import { effEndMs, effStartMs } from "./geometry";

/** Minimum bar span (ms) so a resize/drag can't collapse a bar to zero width. */
export const MIN_DURATION_MS = 60_000;

export type ForestNodeInfo = {
  item: TodoItem;
  parentId: string | null;
  index: number;
  /** 1 = root. */
  level: number;
};

/** Flat `id → { item, parentId, index, level }` over the whole forest. */
export function buildIndex(data: TodoItem[]): Map<string, ForestNodeInfo> {
  const map = new Map<string, ForestNodeInfo>();
  const walk = (items: TodoItem[], parentId: string | null, level: number) => {
    items.forEach((item, index) => {
      map.set(item.id, { item, parentId, index, level });
      if (item.children?.length) walk(item.children, item.id, level + 1);
    });
  };
  walk(data, null, 1);
  return map;
}

/** Replace the matching item via `fn`; returns the same ref when nothing changed. */
function replace(
  data: TodoItem[],
  id: string,
  fn: (item: TodoItem) => TodoItem,
): TodoItem[] {
  let changed = false;
  const next = data.map((item) => {
    if (item.id === id) {
      changed = true;
      return fn(item);
    }
    if (item.children?.length) {
      const kids = replace(item.children, id, fn);
      if (kids !== item.children) {
        changed = true;
        return { ...item, children: kids };
      }
    }
    return item;
  });
  return changed ? next : data;
}

export function renameItem(
  data: TodoItem[],
  id: string,
  name: string,
): TodoItem[] {
  return replace(data, id, (item) => ({ ...item, name }));
}

/**
 * Apply a window patch (reschedule / resize / milestone-move), enforcing the
 * geometry invariant `end ≥ start + MIN_DURATION_MS`. Respects the v1 precedence:
 * an `expireAt`-driven bar keeps writing `expireAt`; a `duration`-driven bar
 * keeps writing `duration`.
 */
export function setWindow(
  data: TodoItem[],
  id: string,
  patch: { startAt?: string; expireAt?: string; duration?: number },
): TodoItem[] {
  return replace(data, id, (item) => {
    const next: TodoItem = { ...item, ...patch };
    const startMs = Date.parse(next.startAt ?? next.setAt);
    if (next.expireAt != null) {
      let endMs = Date.parse(next.expireAt);
      if (
        Number.isFinite(startMs) &&
        Number.isFinite(endMs) &&
        endMs < startMs + MIN_DURATION_MS
      ) {
        endMs = startMs + MIN_DURATION_MS;
      }
      // Guard: an unparseable date would make `new Date(NaN).toISOString()`
      // throw. Leave a bad `expireAt` untouched rather than crashing the commit.
      if (Number.isFinite(endMs)) next.expireAt = new Date(endMs).toISOString();
    } else if (next.duration != null) {
      next.duration = Math.max(MIN_DURATION_MS, next.duration);
    }
    return next;
  });
}

/** True when `maybeAncestorId` is an ancestor of `id` (circular-drop guard). */
export function isAncestor(
  data: TodoItem[],
  maybeAncestorId: string,
  id: string,
): boolean {
  const idx = buildIndex(data);
  let cur = idx.get(id)?.parentId ?? null;
  while (cur != null) {
    if (cur === maybeAncestorId) return true;
    cur = idx.get(cur)?.parentId ?? null;
  }
  return false;
}

/** Insert `item` under `parentId` (null = root) at `index` (default = append). */
export function addItem(
  data: TodoItem[],
  parentId: string | null,
  item: TodoItem,
  index?: number,
): TodoItem[] {
  if (parentId == null) {
    const next = [...data];
    next.splice(index ?? next.length, 0, item);
    return next;
  }
  return replace(data, parentId, (parent) => {
    const kids = parent.children ? [...parent.children] : [];
    kids.splice(index ?? kids.length, 0, item);
    return { ...parent, children: kids };
  });
}

/** Remove an item; returns the new forest + the removed subtree + its old parent. */
export function removeItem(
  data: TodoItem[],
  id: string,
): { next: TodoItem[]; removed: TodoItem | null; parentId: string | null } {
  const info = buildIndex(data).get(id);
  if (!info) return { next: data, removed: null, parentId: null };
  const prune = (items: TodoItem[]): TodoItem[] =>
    items
      .filter((it) => it.id !== id)
      .map((it) =>
        it.children?.length ? { ...it, children: prune(it.children) } : it,
      );
  return { next: prune(data), removed: info.item, parentId: info.parentId };
}

/**
 * Move an item to `newParentId` (null = root) at `newIndex`. The caller guards
 * circular drops (`isAncestor`); `newIndex` is interpreted against the target
 * parent's children AFTER the source has been removed (todo-tree semantics).
 */
export function moveItem(
  data: TodoItem[],
  id: string,
  newParentId: string | null,
  newIndex: number,
): TodoItem[] {
  const { next: pruned, removed } = removeItem(data, id);
  if (!removed) return data;
  return addItem(pruned, newParentId, removed, newIndex);
}

/* ───────── group-move (v0.3.0) ───────── */

/**
 * The scheduled LEAF descendants of `root`. Derived summaries — `root` itself and
 * any nested parent — are never returned; only leaves carry a real schedule.
 * Walks `root.children` directly (no index rebuild), so it's cheap enough for the
 * render-hot `canGroupMove` path. A leaf root yields `[]`.
 */
export function subtreeLeaves(root: TodoItem): TodoItem[] {
  const out: TodoItem[] = [];
  const walk = (n: TodoItem) => {
    if (n.children?.length) n.children.forEach(walk);
    else out.push(n);
  };
  root.children?.forEach(walk); // a summary root ⇒ recurses, never pushes itself
  return out;
}

/**
 * Rigidly shift a subtree by `deltaMs` (group-move). Every LEAF descendant's
 * window translates by the same delta; derived summaries (the root + any nested
 * parent) keep their own latent dates and re-derive their brackets from the moved
 * leaves (WBS-consistent — the gantt ignores a parent's own window). Writes
 * `startAt` (+ `expireAt` for expireAt-driven leaves); `duration`/`setAt`
 * untouched; milestones shift `startAt` only. The span is invariant under a rigid
 * shift, so no MIN_DURATION clamp is needed. Structural sharing; returns the same
 * ref when `deltaMs` is 0 / non-finite.
 */
export function shiftSubtree(
  data: TodoItem[],
  rootId: string,
  deltaMs: number,
): TodoItem[] {
  if (!Number.isFinite(deltaMs) || deltaMs === 0) return data;
  const shiftLeaf = (item: TodoItem): TodoItem => {
    const s = effStartMs(item);
    // Unparseable start — can't translate it; leave the leaf untouched rather
    // than emitting `new Date(NaN).toISOString()` (which throws).
    if (!Number.isFinite(s)) return item;
    const next: TodoItem = {
      ...item,
      startAt: new Date(s + deltaMs).toISOString(),
    };
    if (item.expireAt != null) {
      const e = effEndMs(item);
      const base = e != null && Number.isFinite(e) ? e : s;
      next.expireAt = new Date(base + deltaMs).toISOString();
    }
    return next;
  };
  const shiftDeep = (item: TodoItem): TodoItem =>
    item.children?.length
      ? { ...item, children: item.children.map(shiftDeep) }
      : shiftLeaf(item);
  return replace(data, rootId, shiftDeep);
}

/**
 * Gantt edit-permission resolver. Mirrors todo-tree/lib/permissions.ts: maps the
 * gantt's edit actions onto todo-rich-card's `TodoPermissionRule` keys and
 * resolves against the shared `TodoPermissions` matrix (+ `item.locked`). Keeping
 * the matrix shape identical across card / tree / gantt means one mental model
 * for consumers. Framework-free; Vitest-ready.
 */

import type {
  GanttEditAction,
  TodoItem,
  TodoPermissionRule,
  TodoPermissions,
} from "../types";

/** Gantt actions piggy-back on the most natural existing rule key. */
const ACTION_TO_RULE: Record<GanttEditAction, keyof TodoPermissionRule> = {
  move: "drag",
  resize: "drag",
  delete: "remove",
  create: "addChildren",
  editDetails: "edit",
};

/**
 * Effective allow/deny for one action on `item` at `level` (1 = root). Hard lock
 * (`item.locked`) denies everything. Lookup order byItem → byLevel → default,
 * then a `true` fallback; `inherit !== false` ascends on undefined keys.
 */
export function evalGanttPermission(
  permissions: TodoPermissions | undefined,
  action: GanttEditAction,
  item: TodoItem,
  level: number,
): boolean {
  if (item.locked) return false;
  if (!permissions) return true;

  const key = ACTION_TO_RULE[action];
  const inherit = permissions.inherit !== false;

  const byItem = permissions.byItem?.[item.id]?.[key];
  if (byItem !== undefined) return byItem;
  if (!inherit && permissions.byItem?.[item.id]) return true;

  const byLevel = permissions.byLevel?.[level]?.[key];
  if (byLevel !== undefined) return byLevel;
  if (!inherit && permissions.byLevel?.[level]) return true;

  const def = permissions.default?.[key];
  if (def !== undefined) return def;

  return true;
}

"use client";

import { useEffect, useState } from "react";

/**
 * A counter that increments every `intervalMs` (0 disables). SSR-safe: stays 0
 * on the server + first client render, the interval starts only after mount.
 * Drives the periodic re-resolution of the "now" line + urgency color.
 */
export function useColorTick(intervalMs: number): number {
  const [tick, setTick] = useState(0);
  useEffect(() => {
    if (!intervalMs || intervalMs <= 0) return;
    const id = setInterval(() => setTick((t) => t + 1), intervalMs);
    return () => clearInterval(id);
  }, [intervalMs]);
  return tick;
}

"use client";

import { createContext, useContext } from "react";
import type { GanttContextValue } from "../types";

export const GanttContext = createContext<GanttContextValue | null>(null);

/** Read the gantt context. Throws if used outside `<GanttTimelineRoot>`. */
export function useGanttTimeline(): GanttContextValue {
  const ctx = useContext(GanttContext);
  if (!ctx) {
    throw new Error("useGanttTimeline must be used within <GanttTimelineRoot>");
  }
  return ctx;
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type { GanttViewport, GanttZoom } from "../types";
import { MS, pxPerMsForZoom, timeAt, zoomForPxPerMs } from "../lib/time-scale";

type Args = {
  dataExtent: { startMs: number; endMs: number };
  bodyWidth: number;
  defaultZoom: GanttZoom;
  controlledZoom?: GanttZoom;
  onZoomChange?: (z: GanttZoom) => void;
  minZoom: GanttZoom;
  maxZoom: GanttZoom;
  onViewportChange?: (w: { from: string; to: string }) => void;
  range?: { from: string; to: string };
  nowMs: number;
};

const FRICTION = 0.94;
const MIN_VELOCITY = 0.012; // px/ms

/** Client-only; momentum honors the user's reduced-motion preference (plan §9/§10). */
function prefersReducedMotion(): boolean {
  return (
    typeof window !== "undefined" &&
    typeof window.matchMedia === "function" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches
  );
}

export type GanttViewportApi = {
  viewport: GanttViewport;
  minPxPerMs: number;
  maxPxPerMs: number;
  namedZoom: GanttZoom;
  onPan: (deltaPx: number) => void;
  onZoomAt: (factor: number, focalPx: number) => void;
  zoomBy: (factor: number) => void;
  setZoomLevel: (z: GanttZoom) => void;
  zoomToFit: () => void;
  scrollToMs: (ms: number) => void;
  scrollToToday: () => void;
  pageBy: (dir: -1 | 1) => void;
  beginPan: () => void;
  endPanWithVelocity: (velocityPxPerMs: number) => void;
};

export function useGanttViewport(args: Args): GanttViewportApi {
  const {
    dataExtent,
    bodyWidth,
    defaultZoom,
    controlledZoom,
    onZoomChange,
    minZoom,
    maxZoom,
    onViewportChange,
    range,
    nowMs,
  } = args;

  // hour = most zoomed-in (largest pxPerMs); quarter = most zoomed-out.
  const maxPxPerMs = pxPerMsForZoom(minZoom);
  const minPxPerMs = pxPerMsForZoom(maxZoom);

  const [viewport, setViewport] = useState<GanttViewport>(() => ({
    originMs: dataExtent.startMs,
    pxPerMs: pxPerMsForZoom(defaultZoom),
  }));

  const clampPx = useCallback(
    (px: number) => Math.min(maxPxPerMs, Math.max(minPxPerMs, px)),
    [maxPxPerMs, minPxPerMs],
  );

  const clampOrigin = useCallback(
    (originMs: number, px: number, soft: boolean): number => {
      const visMs = bodyWidth / px;
      const pad = visMs * 0.5;
      const min = dataExtent.startMs - pad;
      const max = dataExtent.endMs + pad - visMs;
      if (max < min) {
        // Data narrower than the viewport — center it.
        return (dataExtent.startMs + dataExtent.endMs) / 2 - visMs / 2;
      }
      if (originMs < min) return soft ? min + (originMs - min) * 0.25 : min;
      if (originMs > max) return soft ? max + (originMs - max) * 0.25 : max;
      return originMs;
    },
    [bodyWidth, dataExtent.startMs, dataExtent.endMs],
  );

  /* ── momentum ── */
  const velRef = useRef(0);
  const rafRef = useRef<number | null>(null);
  const lastTsRef = useRef(0);
  const vcRafRef = useRef<number | null>(null);

  const onPan = useCallback(
    (deltaPx: number) => {
      setViewport((vp) => {
        const proposed = vp.originMs - deltaPx / vp.pxPerMs;
        return { ...vp, originMs: clampOrigin(proposed, vp.pxPerMs, true) };
      });
    },
    [clampOrigin],
  );

  const stopMomentum = useCallback(() => {
    if (rafRef.current != null) cancelAnimationFrame(rafRef.current);
    rafRef.current = null;
    velRef.current = 0;
  }, []);

  const beginPan = useCallback(() => stopMomentum(), [stopMomentum]);

  const endPanWithVelocity = useCallback(
    (velocityPxPerMs: number) => {
      stopMomentum();
      // No inertia fling when the user prefers reduced motion (plan §9/§10).
      if (prefersReducedMotion()) return;
      if (Math.abs(velocityPxPerMs) < MIN_VELOCITY) return;
      velRef.current = velocityPxPerMs;
      lastTsRef.current = 0;
      // hoisted declaration so the rAF loop can self-reference without a TDZ read
      function tick(ts: number) {
        const dt = lastTsRef.current ? ts - lastTsRef.current : 16;
        lastTsRef.current = ts;
        const v = velRef.current;
        if (Math.abs(v) < MIN_VELOCITY) {
          rafRef.current = null;
          return;
        }
        onPan(v * dt);
        velRef.current = v * FRICTION;
        rafRef.current = requestAnimationFrame(tick);
      }
      rafRef.current = requestAnimationFrame(tick);
    },
    [onPan, stopMomentum],
  );

  useEffect(() => () => stopMomentum(), [stopMomentum]);

  /* ── zoom ── */
  const onZoomAt = useCallback(
    (factor: number, focalPx: number) => {
      setViewport((vp) => {
        const focalTime = timeAt(vp, focalPx);
        const newPx = clampPx(vp.pxPerMs * factor);
        const newOrigin = focalTime - focalPx / newPx;
        return { originMs: clampOrigin(newOrigin, newPx, false), pxPerMs: newPx };
      });
    },
    [clampPx, clampOrigin],
  );

  const zoomBy = useCallback(
    (factor: number) => onZoomAt(factor, bodyWidth / 2),
    [onZoomAt, bodyWidth],
  );

  const setZoomLevel = useCallback(
    (z: GanttZoom) => {
      setViewport((vp) => {
        const newPx = clampPx(pxPerMsForZoom(z));
        const centerTime = timeAt(vp, bodyWidth / 2);
        const newOrigin = centerTime - bodyWidth / 2 / newPx;
        return { originMs: clampOrigin(newOrigin, newPx, false), pxPerMs: newPx };
      });
      onZoomChange?.(z);
    },
    [clampPx, clampOrigin, bodyWidth, onZoomChange],
  );

  const zoomToFit = useCallback(() => {
    const dataSpan = dataExtent.endMs - dataExtent.startMs;
    const pad = dataSpan * 0.04 || MS.day;
    const span = dataSpan + pad * 2;
    const px = clampPx(bodyWidth / Math.max(span, 1));
    setViewport({
      originMs: clampOrigin(dataExtent.startMs - pad, px, false),
      pxPerMs: px,
    });
  }, [clampPx, clampOrigin, bodyWidth, dataExtent.startMs, dataExtent.endMs]);

  const scrollToMs = useCallback(
    (ms: number) => {
      setViewport((vp) => {
        const origin = ms - bodyWidth / 2 / vp.pxPerMs;
        return { ...vp, originMs: clampOrigin(origin, vp.pxPerMs, false) };
      });
    },
    [clampOrigin, bodyWidth],
  );

  const scrollToToday = useCallback(() => scrollToMs(nowMs), [scrollToMs, nowMs]);

  const pageBy = useCallback(
    (dir: -1 | 1) => onPan(-dir * bodyWidth * 0.9),
    [onPan, bodyWidth],
  );

  /* ── first-paint fit (cap zoom-in at defaultZoom; honor explicit range) ── */
  const initializedRef = useRef(false);
  useEffect(() => {
    if (bodyWidth <= 0 || initializedRef.current) return;
    initializedRef.current = true;
    if (range) {
      const from = Date.parse(range.from);
      const to = Date.parse(range.to);
      if (Number.isFinite(from) && Number.isFinite(to) && to > from) {
        // eslint-disable-next-line react-hooks/set-state-in-effect
        setViewport({ originMs: from, pxPerMs: clampPx(bodyWidth / (to - from)) });
        return;
      }
    }
    const dataSpan = dataExtent.endMs - dataExtent.startMs;
    const pad = dataSpan * 0.04 || MS.day;
    const span = dataSpan + pad * 2;
    const fitPx = span > 0 ? bodyWidth / span : pxPerMsForZoom(defaultZoom);
    const px = clampPx(Math.min(pxPerMsForZoom(defaultZoom), fitPx));
    const visMs = bodyWidth / px;
    const origin =
      visMs >= dataSpan
        ? (dataExtent.startMs + dataExtent.endMs) / 2 - visMs / 2
        : dataExtent.startMs - pad;
    setViewport({ originMs: origin, pxPerMs: px });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [bodyWidth]);

  /* ── controlled zoom sync ── */
  useEffect(() => {
    if (controlledZoom == null) return;
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setViewport((vp) => {
      const newPx = clampPx(pxPerMsForZoom(controlledZoom));
      if (Math.abs(newPx - vp.pxPerMs) < 1e-12) return vp;
      const centerTime = timeAt(vp, bodyWidth / 2);
      return { originMs: centerTime - bodyWidth / 2 / newPx, pxPerMs: newPx };
    });
  }, [controlledZoom, clampPx, bodyWidth]);

  /* ── viewport-change echo (rAF-throttled: coalesce multiple commits per frame) ── */
  useEffect(() => {
    if (!onViewportChange || bodyWidth <= 0) return;
    if (vcRafRef.current != null) cancelAnimationFrame(vcRafRef.current);
    vcRafRef.current = requestAnimationFrame(() => {
      vcRafRef.current = null;
      onViewportChange({
        from: new Date(timeAt(viewport, 0)).toISOString(),
        to: new Date(timeAt(viewport, bodyWidth)).toISOString(),
      });
    });
    return () => {
      if (vcRafRef.current != null) {
        cancelAnimationFrame(vcRafRef.current);
        vcRafRef.current = null;
      }
    };
  }, [viewport, bodyWidth, onViewportChange]);

  const namedZoom = controlledZoom ?? zoomForPxPerMs(viewport.pxPerMs);

  return {
    viewport,
    minPxPerMs,
    maxPxPerMs,
    namedZoom,
    onPan,
    onZoomAt,
    zoomBy,
    setZoomLevel,
    zoomToFit,
    scrollToMs,
    scrollToToday,
    pageBy,
    beginPan,
    endPanWithVelocity,
  };
}

"use client";

import { useVirtualizer } from "@tanstack/react-virtual";
import type { RefObject } from "react";
import type { GanttRenderItem } from "../types";

/**
 * Row virtualization (mirrors todo-tree's `use-tree-virtual`). Virtualizes when
 * the row count crosses `threshold` AND a scroll element exists; otherwise
 * returns every row at its natural offset (the gutter-only / small-list
 * fallback). Both the gutter and the body consume the returned `renderItems`,
 * so they share one source of truth and stay vertically aligned.
 */
export function useGanttVirtual(args: {
  count: number;
  scrollRef: RefObject<HTMLDivElement | null>;
  rowHeight: number;
  threshold?: number;
}): { renderItems: GanttRenderItem[]; totalSize: number; measure: () => void } {
  const { count, scrollRef, rowHeight, threshold = 60 } = args;
  const active = count >= threshold;

  const virtualizer = useVirtualizer<HTMLDivElement, HTMLDivElement>({
    count,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => rowHeight,
    overscan: 8,
    enabled: active,
  });

  if (active) {
    const renderItems: GanttRenderItem[] = virtualizer
      .getVirtualItems()
      .map((vi) => ({ index: vi.index, start: vi.start }));
    return {
      renderItems,
      totalSize: virtualizer.getTotalSize(),
      measure: () => virtualizer.measure(),
    };
  }

  const renderItems: GanttRenderItem[] = Array.from(
    { length: count },
    (_, index) => ({ index, start: index * rowHeight }),
  );
  return { renderItems, totalSize: count * rowHeight, measure: () => {} };
}

"use client";

/**
 * The editing state machine (v0.2.0). Owns the transient edit-UI targets
 * (detail-editor + inline-rename) and the mutation dispatchers. Every dispatcher
 * is a single chokepoint: re-check permission (veto-before-dispatch), compute the
 * NEXT forest from `data` via the pure `edit-mutations`, fire the typed
 * todo-rich-card-shaped event, then `onChange(next)`. No internal copy of `data`
 * — the controlled consumer echoes. When `editable` is false, `can()` returns
 * false so every dispatcher no-ops (the v1 read-only guarantee).
 */

import { useCallback, useMemo, useState } from "react";
import type {
  GanttComposerTarget,
  GanttEditAction,
  GanttSnap,
  TodoFieldEditedEvent,
  TodoItem,
  TodoItemAddedEvent,
  TodoItemMovedEvent,
  TodoItemRemovedEvent,
  TodoPermissionReason,
  TodoPermissionRule,
  TodoPermissions,
  TodoStatusChangedEvent,
  TodoStatusOption,
} from "../types";
import {
  addItem,
  buildIndex,
  isAncestor,
  moveItem,
  removeItem,
  renameItem,
  setWindow,
  shiftSubtree,
  subtreeLeaves,
} from "../lib/edit-mutations";
import { evalGanttPermission } from "../lib/edit-permissions";
import {
  copyTasksToClipboard,
  reassignTaskIds,
} from "../../todo-rich-card/lib/clipboard";

type Args = {
  data: TodoItem[];
  editable: boolean;
  snap: GanttSnap;
  statusOptions?: TodoStatusOption[];
  onChange?: (data: TodoItem[]) => void;
  onTaskReschedule?: (next: {
    itemId: string;
    startAt: string;
    expireAt?: string;
  }) => void;
  onItemAdded?: (e: TodoItemAddedEvent) => void;
  onItemRemoved?: (e: TodoItemRemovedEvent) => void;
  onItemMoved?: (e: TodoItemMovedEvent) => void;
  onFieldEdited?: (e: TodoFieldEditedEvent) => void;
  onStatusChanged?: (e: TodoStatusChangedEvent) => void;
  permissions?: TodoPermissions;
  canMoveItem?: (id: string) => boolean;
  canResizeItem?: (id: string) => boolean;
  canDeleteItem?: (id: string) => boolean;
  canCreateChild?: (id: string) => boolean;
  canEditItem?: (id: string) => boolean;
  onPermissionDenied?: (
    action: keyof TodoPermissionRule,
    itemId: string,
    reason: TodoPermissionReason,
  ) => void;
};

const ACTION_RULE: Record<GanttEditAction, keyof TodoPermissionRule> = {
  move: "drag",
  resize: "drag",
  delete: "remove",
  create: "addChildren",
  editDetails: "edit",
};

function freshId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return `gt-${crypto.randomUUID()}`;
  }
  return `gt-${Math.random().toString(36).slice(2)}-${Math.random().toString(36).slice(2)}`;
}

export function useGanttEdit(args: Args) {
  const {
    data,
    editable,
    snap,
    statusOptions,
    onChange,
    onTaskReschedule,
    onItemAdded,
    onItemRemoved,
    onItemMoved,
    onFieldEdited,
    onStatusChanged,
    permissions,
    canMoveItem,
    canResizeItem,
    canDeleteItem,
    canCreateChild,
    canEditItem,
    onPermissionDenied,
  } = args;

  const index = useMemo(() => buildIndex(data), [data]);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [renamingId, setRenamingId] = useState<string | null>(null);
  const [composerTarget, setComposerTarget] =
    useState<GanttComposerTarget | null>(null);

  const nodeInfo = useCallback(
    (id: string) => {
      const info = index.get(id);
      return info
        ? { parentId: info.parentId, index: info.index, level: info.level }
        : undefined;
    },
    [index],
  );

  const predicateFor = useCallback(
    (action: GanttEditAction): ((id: string) => boolean) | undefined => {
      switch (action) {
        case "move":
          return canMoveItem;
        case "resize":
          return canResizeItem;
        case "delete":
          return canDeleteItem;
        case "create":
          return canCreateChild;
        case "editDetails":
          return canEditItem;
      }
    },
    [canMoveItem, canResizeItem, canDeleteItem, canCreateChild, canEditItem],
  );

  const can = useCallback(
    (action: GanttEditAction, item: TodoItem): boolean => {
      if (!editable) return false;
      const level = index.get(item.id)?.level ?? 1;
      if (!evalGanttPermission(permissions, action, item, level)) return false;
      const pred = predicateFor(action);
      if (pred && !pred(item.id)) return false;
      return true;
    },
    [editable, index, permissions, predicateFor],
  );

  /** Guard a dispatch: return the item if allowed, else report denial + null. */
  const guard = useCallback(
    (action: GanttEditAction, id: string): TodoItem | null => {
      const item = index.get(id)?.item;
      if (!item) return null;
      if (can(action, item)) return item;
      const reason: TodoPermissionReason = item.locked
        ? "locked"
        : predicateFor(action)?.(id) === false
          ? "predicate"
          : "default";
      onPermissionDenied?.(ACTION_RULE[action], id, reason);
      return null;
    },
    [index, can, predicateFor, onPermissionDenied],
  );

  const rescheduleItem = useCallback(
    (
      id: string,
      patch: { startAt?: string; expireAt?: string; duration?: number },
      kind: "move" | "resize",
    ) => {
      const item = guard(kind, id);
      if (!item) return;
      const next = setWindow(data, id, patch);
      if (next === data) return;
      const updated = buildIndex(next).get(id)?.item;
      if (!updated) return;
      // Each field event is gated on the patch actually touching that key AND on
      // the value really changing. `setWindow` re-serializes `expireAt` whenever
      // the item has one (even on a start-only resize), so compare by instant —
      // a non-canonical stored date (e.g. `+03:00` offset) must not fire a phantom
      // event whose old/new are the same moment.
      if (
        patch.startAt != null &&
        Date.parse(updated.startAt ?? "") !== Date.parse(item.startAt ?? "")
      ) {
        onFieldEdited?.({
          itemId: id,
          key: "startAt",
          oldValue: item.startAt,
          newValue: updated.startAt,
        });
      }
      if (
        patch.expireAt != null &&
        Date.parse(updated.expireAt ?? "") !== Date.parse(item.expireAt ?? "")
      ) {
        onFieldEdited?.({
          itemId: id,
          key: "expireAt",
          oldValue: item.expireAt,
          newValue: updated.expireAt,
        });
      }
      if (patch.duration != null && updated.duration !== item.duration) {
        onFieldEdited?.({
          itemId: id,
          key: "duration",
          oldValue: item.duration,
          newValue: updated.duration,
        });
      }
      onTaskReschedule?.({
        itemId: id,
        startAt: updated.startAt ?? updated.setAt,
        expireAt: updated.expireAt,
      });
      onChange?.(next);
    },
    [data, guard, onFieldEdited, onTaskReschedule, onChange],
  );

  const createItem = useCallback(
    (
      parentId: string | null,
      seed?: Partial<TodoItem>,
      at?: number,
      opts?: { openEditor?: boolean },
    ) => {
      // Root create gates on `editable` only; child create gates the PARENT's
      // addChildren rule.
      if (!editable) return;
      if (parentId != null && !guard("create", parentId)) return;
      const nowIso = seed?.setAt ?? new Date().toISOString();
      const item: TodoItem = {
        id: seed?.id ?? freshId(),
        name: seed?.name ?? "New task",
        status: seed?.status ?? statusOptions?.[0]?.value ?? "todo",
        active: seed?.active ?? true,
        setAt: nowIso,
        ...seed,
      };
      const next = addItem(data, parentId, item, at);
      onItemAdded?.({ parentId: parentId ?? "", item });
      onChange?.(next);
      // v0.5.0 — quick-composer "More options" opens the detail editor on the new item.
      if (opts?.openEditor) setEditingId(item.id);
    },
    [editable, guard, statusOptions, data, onItemAdded, onChange],
  );

  const deleteItem = useCallback(
    (id: string) => {
      if (!guard("delete", id)) return;
      const { next, removed, parentId } = removeItem(data, id);
      if (!removed) return;
      onItemRemoved?.({ itemId: id, removed, parentId: parentId ?? "" });
      onChange?.(next);
      if (editingId === id) setEditingId(null);
      if (renamingId === id) setRenamingId(null);
    },
    [data, guard, onItemRemoved, onChange, editingId, renamingId],
  );

  const renameItemAction = useCallback(
    (id: string, name: string) => {
      const item = guard("editDetails", id);
      if (!item || name === item.name) return;
      const next = renameItem(data, id, name);
      onFieldEdited?.({
        itemId: id,
        key: "name",
        oldValue: item.name,
        newValue: name,
      });
      onChange?.(next);
    },
    [data, guard, onFieldEdited, onChange],
  );

  const moveItemAction = useCallback(
    (id: string, newParentId: string | null, newIndex: number) => {
      const item = guard("move", id);
      if (!item) return;
      // Circular drop is a structural invalid, not a permission denial — no-op.
      if (newParentId != null && (newParentId === id || isAncestor(data, id, newParentId)))
        return;
      const from = index.get(id);
      // Same-parent move-down: removing the source shifts indices, so the drop
      // index is one too far. (todo-tree semantics.)
      let targetIndex = newIndex;
      if (from && (from.parentId ?? null) === newParentId && from.index < newIndex) {
        targetIndex = newIndex - 1;
      }
      const next = moveItem(data, id, newParentId, targetIndex);
      if (next === data) return;
      onItemMoved?.({
        itemId: id,
        oldParentId: from?.parentId ?? "",
        newParentId: newParentId ?? "",
        oldIndex: from?.index ?? 0,
        newIndex: targetIndex,
      });
      onChange?.(next);
    },
    [data, guard, index, onItemMoved, onChange],
  );

  /* ── group-move (v0.3.0) ── */

  /** Atomic gate: the summary is movable AND every descendant leaf is movable. */
  const canGroupMove = useCallback(
    (item: TodoItem): boolean => {
      if (!editable || !can("move", item)) return false;
      const leaves = subtreeLeaves(item);
      return leaves.length > 0 && leaves.every((l) => can("move", l));
    },
    [editable, can],
  );

  /** Shift a summary's whole subtree by `deltaMs` — single-move applied per leaf. */
  const moveSubtree = useCallback(
    (id: string, deltaMs: number) => {
      const summary = guard("move", id); // reports denial if the summary itself is blocked
      if (!summary) return;
      const leaves = subtreeLeaves(summary);
      if (leaves.length === 0) return;
      // Atomic (D23): a single blocked leaf vetoes the whole group; report + abort.
      for (const leaf of leaves) {
        if (!can("move", leaf)) {
          const reason: TodoPermissionReason = leaf.locked
            ? "locked"
            : canMoveItem?.(leaf.id) === false
              ? "predicate"
              : "default";
          onPermissionDenied?.("drag", leaf.id, reason);
          return;
        }
      }
      if (deltaMs === 0) return;
      const next = shiftSubtree(data, id, deltaMs);
      if (next === data) return;
      const nextIndex = buildIndex(next);
      // D25 — per-leaf field events (parity with single-move) + one onChange (= one undo step).
      for (const leaf of leaves) {
        const updated = nextIndex.get(leaf.id)?.item;
        if (!updated) continue;
        onFieldEdited?.({
          itemId: leaf.id,
          key: "startAt",
          oldValue: leaf.startAt,
          newValue: updated.startAt,
        });
        if (updated.expireAt !== leaf.expireAt) {
          onFieldEdited?.({
            itemId: leaf.id,
            key: "expireAt",
            oldValue: leaf.expireAt,
            newValue: updated.expireAt,
          });
        }
        onTaskReschedule?.({
          itemId: leaf.id,
          startAt: updated.startAt ?? updated.setAt,
          expireAt: updated.expireAt,
        });
      }
      onChange?.(next);
    },
    [
      data,
      can,
      guard,
      canMoveItem,
      onPermissionDenied,
      onFieldEdited,
      onTaskReschedule,
      onChange,
    ],
  );

  const changeStatus = useCallback(
    (id: string, status: string) => {
      const item = guard("editDetails", id);
      if (!item || status === item.status) return;
      const apply = (items: TodoItem[]): TodoItem[] =>
        items.map((it) =>
          it.id === id
            ? { ...it, status }
            : it.children?.length
              ? { ...it, children: apply(it.children) }
              : it,
        );
      onStatusChanged?.({ itemId: id, oldStatus: item.status, newStatus: status });
      onFieldEdited?.({
        itemId: id,
        key: "status",
        oldValue: item.status,
        newValue: status,
      });
      onChange?.(apply(data));
    },
    [data, guard, onStatusChanged, onFieldEdited, onChange],
  );

  const changePriority = useCallback(
    (id: string, priority: string) => {
      const item = guard("editDetails", id);
      if (!item || priority === item.priority) return;
      // "priority" is not a `TodoEditableField`, so no typed field event — the
      // forest echo carries it (parity with calendar + the card).
      const apply = (items: TodoItem[]): TodoItem[] =>
        items.map((it) =>
          it.id === id
            ? { ...it, priority }
            : it.children?.length
              ? { ...it, children: apply(it.children) }
              : it,
        );
      onChange?.(apply(data));
    },
    [data, guard, onChange],
  );

  /* ── quick-create composer (v0.5.0) ── */
  const openComposer = useCallback(
    (target: GanttComposerTarget) => {
      if (!editable) return;
      // Gate the create up-front so we never float a composer that will no-op.
      if (target.parentId != null && !guard("create", target.parentId)) return;
      setComposerTarget(target);
    },
    [editable, guard],
  );
  const closeComposer = useCallback(() => setComposerTarget(null), []);

  /* ── cross-surface clipboard (v0.5.0) ── */
  const copyItem = useCallback(
    (id: string) => {
      const item = index.get(id)?.item;
      if (!item) return;
      void copyTasksToClipboard([item], "gantt-timeline-01");
    },
    [index],
  );
  const cutItem = useCallback(
    (id: string) => {
      const item = guard("delete", id);
      if (!item) return;
      void copyTasksToClipboard([item], "gantt-timeline-01");
      deleteItem(id);
    },
    [guard, deleteItem],
  );
  const pasteTasks = useCallback(
    (items: TodoItem[], parentId: string | null, atIndex?: number) => {
      if (!editable || items.length === 0) return;
      if (parentId != null && !guard("create", parentId)) return;
      let next = data;
      const created: TodoItem[] = [];
      let at = atIndex;
      for (const raw of items) {
        // Re-id every grafted subtree so a paste can't collide; dates preserved
        // (gantt has no "drop window" — the bar lands where it was copied from).
        const root = reassignTaskIds(raw);
        next = addItem(next, parentId, root, at);
        created.push(root);
        if (at != null) at += 1;
      }
      if (next === data) return;
      created.forEach((item) =>
        onItemAdded?.({ parentId: parentId ?? "", item }),
      );
      onChange?.(next);
    },
    [editable, guard, data, onItemAdded, onChange],
  );

  /** Splice an edited subtree (same root id) from the embedded card back in. */
  const applyEditedSubtree = useCallback(
    (nextItem: TodoItem) => {
      const prev = index.get(nextItem.id)?.item;
      if (!prev) {
        // The item was deleted (another path) while its editor was open. Splicing
        // an absent id would be a no-op map and echo the UNCHANGED forest, silently
        // dropping the edit. Drop the stale edit and close instead.
        setEditingId(null);
        return;
      }
      const apply = (items: TodoItem[]): TodoItem[] =>
        items.map((it) =>
          it.id === nextItem.id
            ? nextItem
            : it.children?.length
              ? { ...it, children: apply(it.children) }
              : it,
        );
      const forest = apply(data);
      if (prev.status !== nextItem.status) {
        onStatusChanged?.({
          itemId: nextItem.id,
          oldStatus: prev.status,
          newStatus: nextItem.status,
        });
      }
      onChange?.(forest);
    },
    [data, index, onStatusChanged, onChange],
  );

  const openEditor = useCallback(
    (id: string) => {
      if (guard("editDetails", id)) setEditingId(id);
    },
    [guard],
  );
  const closeEditor = useCallback(() => setEditingId(null), []);
  const beginRename = useCallback(
    (id: string) => {
      if (guard("editDetails", id)) setRenamingId(id);
    },
    [guard],
  );
  const endRename = useCallback(() => setRenamingId(null), []);

  return {
    editable,
    snap,
    can,
    canGroupMove,
    nodeInfo,
    rescheduleItem,
    createItem,
    deleteItem,
    renameItemAction,
    moveItemAction,
    moveSubtree,
    changeStatus,
    changePriority,
    editingId,
    openEditor,
    closeEditor,
    applyEditedSubtree,
    renamingId,
    beginRename,
    endRename,
    composerTarget,
    openComposer,
    closeComposer,
    copyItem,
    cutItem,
    pasteTasks,
  };
}

"use client";

import { lazy, Suspense } from "react";
import type { TodoItem } from "../types";

// The ONLY module that imports todo-rich-card's VALUE, and only lazily — so the
// card never enters a consumer's bundle unless they opt into the full-card
// tooltip via `renderTooltip={(item) => <GanttFullCardTooltip item={item} />}`.
const TodoRichCardLazy = lazy(() =>
  import("../../todo-rich-card").then((m) => ({ default: m.TodoRichCard })),
);

export function GanttFullCardTooltip({ item }: { item: TodoItem }) {
  return (
    <div className="w-72">
      <Suspense
        fallback={
          <div className="p-2 text-xs text-muted-foreground">Loading…</div>
        }
      >
        <TodoRichCardLazy defaultValue={item} editable={false} />
      </Suspense>
    </div>
  );
}

"use client";

/**
 * Tier-C right-click action menu (v0.2.0). Wraps a target (a body bar row or a
 * gutter row) and offers permission-gated Edit / Rename / Add child / Add sibling
 * / Status / Delete. Every action routes through the same `use-gantt-edit`
 * dispatchers as the pointer + keyboard paths (single mutation chokepoint). When
 * editing is off or nothing is permitted, it renders the child unwrapped — zero
 * overhead in the v1 read-only path.
 */

import type { ReactNode } from "react";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuSub,
  ContextMenuSubContent,
  ContextMenuSubTrigger,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { TodoItem } from "../types";

export function GanttContextMenu({
  item,
  children,
}: {
  item: TodoItem;
  children: ReactNode;
}) {
  const ctx = useGanttTimeline();

  const canEdit = ctx.editable && ctx.can("editDetails", item);
  // "Add child task" creates UNDER this item → gated on the item's own rule.
  const canCreate = ctx.editable && ctx.can("create", item);
  // "Add task below" creates a SIBLING under this item's PARENT → must gate on the
  // parent's rule (which is what `createItem` actually enforces), else the item
  // shows then no-ops + fires onPermissionDenied. Root items (no parent) gate on
  // `editable` only, matching `createItem`'s root-insert path.
  const parentId = ctx.nodeInfo(item.id)?.parentId ?? null;
  const parentNode = parentId != null ? ctx.getItem(parentId) : null;
  const canCreateSibling =
    ctx.editable &&
    (parentId == null ? true : !!parentNode && ctx.can("create", parentNode));
  const canDelete = ctx.editable && ctx.can("delete", item);
  const statusOptions = ctx.statusOptions ?? [];
  const priorityOptions = ctx.priorityOptions ?? [];

  if (!canEdit && !canCreate && !canCreateSibling && !canDelete)
    return <>{children}</>;

  return (
    <ContextMenu>
      <ContextMenuTrigger asChild>{children}</ContextMenuTrigger>
      <ContextMenuContent className="w-48">
        {canEdit ? (
          <>
            <ContextMenuItem onSelect={() => ctx.openEditor(item.id)}>
              Edit…
            </ContextMenuItem>
            <ContextMenuItem onSelect={() => ctx.beginRename(item.id)}>
              Rename
            </ContextMenuItem>
          </>
        ) : null}

        {canCreate ? (
          <ContextMenuItem onSelect={() => ctx.createItem(item.id)}>
            Add child task
          </ContextMenuItem>
        ) : null}

        {canCreateSibling ? (
          <ContextMenuItem
            onSelect={() => {
              const info = ctx.nodeInfo(item.id);
              ctx.createItem(
                info?.parentId ?? null,
                undefined,
                (info?.index ?? 0) + 1,
              );
            }}
          >
            Add task below
          </ContextMenuItem>
        ) : null}

        {canEdit && statusOptions.length > 0 ? (
          <>
            <ContextMenuSeparator />
            <ContextMenuSub>
              <ContextMenuSubTrigger>Status</ContextMenuSubTrigger>
              <ContextMenuSubContent>
                {statusOptions.map((o) => (
                  <ContextMenuItem
                    key={o.value}
                    onSelect={() => ctx.changeStatus(item.id, o.value)}
                  >
                    {o.icon ? `${o.icon} ` : ""}
                    {o.label}
                  </ContextMenuItem>
                ))}
              </ContextMenuSubContent>
            </ContextMenuSub>
          </>
        ) : null}

        {canEdit && priorityOptions.length > 0 ? (
          <ContextMenuSub>
            <ContextMenuSubTrigger>Priority</ContextMenuSubTrigger>
            <ContextMenuSubContent>
              {priorityOptions.map((o) => (
                <ContextMenuItem
                  key={o.value}
                  onSelect={() => ctx.changePriority(item.id, o.value)}
                >
                  {o.label}
                </ContextMenuItem>
              ))}
            </ContextMenuSubContent>
          </ContextMenuSub>
        ) : null}

        <ContextMenuSeparator />
        <ContextMenuItem onSelect={() => ctx.copyItem(item.id)}>
          Copy
        </ContextMenuItem>
        {canDelete ? (
          <ContextMenuItem onSelect={() => ctx.cutItem(item.id)}>
            Cut
          </ContextMenuItem>
        ) : null}

        {canDelete ? (
          <>
            <ContextMenuSeparator />
            <ContextMenuItem
              variant="destructive"
              onSelect={() => ctx.deleteItem(item.id)}
            >
              Delete
            </ContextMenuItem>
          </>
        ) : null}
      </ContextMenuContent>
    </ContextMenu>
  );
}

"use client";

/**
 * Detail editor (v0.2.0). A centered modal overlay — a plain backdrop + panel,
 * NOT the shadcn `popover` primitive — so it sidesteps the Radix/Base-UI `asChild`
 * divergence the v1 tooltip avoided the same way. It hosts the lazy
 * `<TodoRichCard editable>`; the card's `onChange` subtree is spliced back into
 * the forest via `applyEditedSubtree`. The card VALUE loads only when an editor
 * actually opens (React.lazy), so it never weighs on the default bundle.
 */

import { Suspense, lazy, useEffect } from "react";
import { useGanttTimeline } from "../hooks/use-gantt-context";

const TodoRichCardLazy = lazy(() =>
  import("../../todo-rich-card").then((m) => ({ default: m.TodoRichCard })),
);

export function GanttEditPopover() {
  const ctx = useGanttTimeline();
  const id = ctx.editingId;
  const closeEditor = ctx.closeEditor;

  useEffect(() => {
    if (id == null) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") closeEditor();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [id, closeEditor]);

  if (id == null) return null;
  const item = ctx.getItem(id);
  if (!item) return null;

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label={`Edit ${item.name}`}
      className="fixed inset-0 z-50 flex items-center justify-center p-4"
    >
      <button
        type="button"
        aria-label="Close editor"
        onClick={closeEditor}
        className="absolute inset-0 cursor-default bg-background/70 backdrop-blur-sm"
      />
      <div className="relative z-10 w-full max-w-sm">
        <Suspense
          fallback={
            <div className="rounded-lg border border-border bg-card p-6 text-center text-sm text-muted-foreground">
              Loading editor…
            </div>
          }
        >
          <TodoRichCardLazy
            value={item}
            editable
            statusOptions={ctx.statusOptions}
            priorityOptions={ctx.priorityOptions}
            labelOptions={ctx.labelOptions}
            permissions={ctx.permissions}
            onChange={(next) => ctx.applyEditedSubtree(next)}
          />
        </Suspense>
        <div className="mt-2 flex justify-end">
          <button
            type="button"
            onClick={closeEditor}
            className="rounded-md border border-border bg-card px-3 py-1.5 text-xs font-medium text-foreground transition-colors hover:bg-muted"
          >
            Done
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

/**
 * Quick-create composer (Tier B + Tier C). When a double-click on an empty row
 * area sets `composerTarget`, this floats a small title-entry popup at the
 * pointer: type a name + Enter to create, or "More options" to open the full
 * editor on the new task. Deliberately a plain fixed-position panel (NOT a Radix
 * Popover) to dodge the Base-UI anchor/asChild divergence — mirrors calendar's
 * quick-composer. A native `<select>` keeps the status pick dep-free.
 *
 * Mounted by the Root (lives inside `GanttTimelineRoot`); reads context.
 */

import { useState } from "react";
import type { ReactNode } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type {
  GanttComposerTarget,
  GanttContextValue,
  TodoItem,
} from "../types";

const iso = (ms: number) => new Date(ms).toISOString();

function whenText(t: GanttComposerTarget): string {
  const start = new Date(t.startMs).toLocaleDateString();
  if (t.endMs == null || t.endMs <= t.startMs) return start;
  const end = new Date(t.endMs).toLocaleDateString();
  return start === end ? start : `${start} → ${end}`;
}

function Floating({
  x,
  y,
  onClose,
  children,
}: {
  x: number;
  y: number;
  onClose: () => void;
  children: ReactNode;
}) {
  return (
    <>
      <div className="fixed inset-0 z-40" onClick={onClose} aria-hidden />
      <div
        role="dialog"
        aria-label="Create task"
        className="fixed z-50 w-64 rounded-lg border border-border bg-popover p-3 text-popover-foreground shadow-lg"
        style={{ left: x, top: y }}
      >
        {children}
      </div>
    </>
  );
}

function ComposerPopup({
  target,
  onClose,
  onCreate,
  statusOptions,
  render,
}: {
  target: GanttComposerTarget;
  onClose: () => void;
  onCreate: GanttContextValue["createItem"];
  statusOptions: GanttContextValue["statusOptions"];
  render?: GanttContextValue["renderQuickComposer"];
}) {
  const [title, setTitle] = useState("");
  const [status, setStatus] = useState(statusOptions?.[0]?.value ?? "");

  const seedOf = (extra?: Partial<TodoItem>): Partial<TodoItem> => ({
    name: title.trim() || "New task",
    startAt: iso(target.startMs),
    setAt: iso(target.startMs),
    ...(target.endMs != null ? { expireAt: iso(target.endMs) } : {}),
    ...(status ? { status } : {}),
    ...extra,
  });
  const commit = (extra?: Partial<TodoItem>) => {
    onCreate(target.parentId, seedOf(extra), target.index);
    onClose();
  };
  const openFull = () => {
    onCreate(target.parentId, seedOf(), target.index, { openEditor: true });
    onClose();
  };

  const vw = typeof window !== "undefined" ? window.innerWidth : 1024;
  const vh = typeof window !== "undefined" ? window.innerHeight : 768;
  const px = Math.max(8, Math.min(target.x ?? 80, vw - 272));
  const py = Math.max(8, Math.min(target.y ?? 80, vh - 200));

  if (render) {
    return (
      <Floating x={px} y={py} onClose={onClose}>
        {render({
          startMs: target.startMs,
          endMs: target.endMs,
          commit: (seed) => commit(seed),
          cancel: onClose,
          openFull,
        })}
      </Floating>
    );
  }

  return (
    <Floating x={px} y={py} onClose={onClose}>
      <form
        onSubmit={(e) => {
          e.preventDefault();
          commit();
        }}
        className="flex flex-col gap-2"
      >
        <p className="text-xs text-muted-foreground">{whenText(target)}</p>
        <Input
          autoFocus
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Escape") onClose();
          }}
          placeholder="Task name"
          className="h-8"
        />
        {statusOptions && statusOptions.length > 0 ? (
          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="h-8 rounded-md border border-input bg-transparent px-2 text-sm outline-none focus-visible:ring-2 focus-visible:ring-ring/50"
            aria-label="Status"
          >
            {statusOptions.map((o) => (
              <option key={o.value} value={o.value}>
                {o.label}
              </option>
            ))}
          </select>
        ) : null}
        <div className="flex items-center justify-between">
          <button
            type="button"
            onClick={openFull}
            className="text-xs text-muted-foreground underline-offset-2 hover:text-foreground hover:underline"
          >
            More options
          </button>
          <div className="flex gap-1.5">
            <Button type="button" size="sm" variant="ghost" onClick={onClose}>
              Cancel
            </Button>
            <Button type="submit" size="sm">
              Create
            </Button>
          </div>
        </div>
      </form>
    </Floating>
  );
}

export function GanttQuickComposer() {
  const { composerTarget, closeComposer, createItem, renderQuickComposer, statusOptions } =
    useGanttTimeline();
  if (!composerTarget) return null;
  return (
    <ComposerPopup
      key={`${composerTarget.startMs}:${composerTarget.x ?? 0}:${composerTarget.y ?? 0}`}
      target={composerTarget}
      onClose={closeComposer}
      onCreate={createItem}
      statusOptions={statusOptions}
      render={renderQuickComposer}
    />
  );
}

"use client";

import type { HTMLAttributes } from "react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { TodoItem, TodoStatusOption } from "../types";
import { effEndMs, effStartMs } from "../lib/geometry";

/* ───────── helpers ───────── */

function initials(name: string): string {
  return name
    .split(/\s+/)
    .map((p) => p[0])
    .filter(Boolean)
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

function fmtDate(ms: number): string {
  return new Intl.DateTimeFormat(undefined, {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(new Date(ms));
}

/* ───────── GanttBar (Tier C) ───────── */

export type GanttBarProps = {
  leftPx: number;
  widthPx: number;
  fill: string;
  rowHeight: number;
  overdue?: boolean;
  inactive?: boolean;
  locked?: boolean;
  priorityColor?: string;
  selected?: boolean;
  /** v0.2.0 — grab cursor for drag-to-reschedule. */
  movable?: boolean;
  /** v0.2.0 — render left/right edge resize handles (`data-edge`). */
  resizable?: boolean;
} & HTMLAttributes<HTMLDivElement>;

export function GanttBar({
  leftPx,
  widthPx,
  fill,
  rowHeight,
  overdue,
  inactive,
  locked,
  priorityColor,
  selected,
  movable,
  resizable,
  className,
  style,
  ...rest
}: GanttBarProps) {
  const barH = Math.max(10, Math.min(rowHeight - 12, 22));
  return (
    <div
      data-selected={selected || undefined}
      className={cn(
        "absolute top-1/2 -translate-y-1/2 rounded-[5px] shadow-sm ring-offset-background transition-shadow",
        movable ? "cursor-grab active:cursor-grabbing" : "cursor-pointer",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        "data-[selected]:ring-2 data-[selected]:ring-foreground/70 data-[selected]:ring-offset-1",
        inactive && "opacity-50",
        className,
      )}
      style={{
        left: leftPx,
        width: Math.max(widthPx, 6),
        height: barH,
        background: fill,
        ...style,
      }}
      {...rest}
    >
      {priorityColor ? (
        <span
          aria-hidden
          className="absolute left-0 top-0 h-full w-1 rounded-l-[5px]"
          style={{ background: priorityColor }}
        />
      ) : null}
      {overdue ? (
        <span
          aria-hidden
          className="absolute inset-y-0 right-0 w-1.5 rounded-r-[5px] bg-destructive"
        />
      ) : null}
      {locked ? (
        <span
          aria-hidden
          className="absolute right-1 top-1/2 -translate-y-1/2 text-[9px] leading-none text-background/80"
        >
          🔒
        </span>
      ) : null}
      {resizable ? (
        <>
          <span
            data-edge="start"
            aria-hidden
            className="absolute inset-y-0 left-0 w-2 cursor-col-resize rounded-l-[5px] hover:bg-foreground/25"
          />
          <span
            data-edge="end"
            aria-hidden
            className="absolute inset-y-0 right-0 w-2 cursor-col-resize rounded-r-[5px] hover:bg-foreground/25"
          />
        </>
      ) : null}
    </div>
  );
}

/* ───────── SummaryBar (Tier C) ───────── */

export type SummaryBarProps = {
  leftPx: number;
  widthPx: number;
  selected?: boolean;
  /** v0.3.0 — grab cursor + enlarged hit area for group-move (drag → shift subtree). */
  groupMovable?: boolean;
} & HTMLAttributes<HTMLDivElement>;

export function SummaryBar({
  leftPx,
  widthPx,
  selected,
  groupMovable,
  className,
  style,
  ...rest
}: SummaryBarProps) {
  return (
    <div
      data-selected={selected || undefined}
      className={cn(
        "absolute top-1/2 -translate-y-1/2 rounded-sm bg-foreground/85",
        groupMovable ? "cursor-grab active:cursor-grabbing" : "cursor-pointer",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring",
        "data-[selected]:ring-2 data-[selected]:ring-foreground",
        className,
      )}
      style={{ left: leftPx, width: Math.max(widthPx, 8), height: 7, ...style }}
      {...rest}
    >
      {/* enlarged pointer hit area (visual stays a thin 7px bar) */}
      {groupMovable ? (
        <span aria-hidden className="absolute -inset-y-2 inset-x-0" />
      ) : null}
      {/* bracket end-caps */}
      <span
        aria-hidden
        className="absolute -bottom-1 left-0 h-2 w-1.5 -skew-x-[20deg] bg-foreground/85"
      />
      <span
        aria-hidden
        className="absolute -bottom-1 right-0 h-2 w-1.5 skew-x-[20deg] bg-foreground/85"
      />
    </div>
  );
}

/* ───────── MilestoneDiamond (Tier C) ───────── */

export type MilestoneDiamondProps = {
  leftPx: number;
  fill: string;
  selected?: boolean;
  /** v0.2.0 — grab cursor for drag-to-move the instant. */
  movable?: boolean;
} & HTMLAttributes<HTMLDivElement>;

export function MilestoneDiamond({
  leftPx,
  fill,
  selected,
  movable,
  className,
  style,
  ...rest
}: MilestoneDiamondProps) {
  const size = 13;
  return (
    <div
      data-selected={selected || undefined}
      className={cn(
        "absolute top-1/2 rounded-[3px] shadow-sm",
        movable ? "cursor-grab active:cursor-grabbing" : "cursor-pointer",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring",
        "data-[selected]:ring-2 data-[selected]:ring-foreground/70",
        className,
      )}
      style={{
        left: leftPx - size / 2,
        width: size,
        height: size,
        transform: "translateY(-50%) rotate(45deg)",
        background: fill,
        ...style,
      }}
      {...rest}
    />
  );
}

/* ───────── TodayLine (Tier C) ───────── */

export function TodayLine({ leftPx }: { leftPx: number }) {
  return (
    <div
      aria-hidden
      className="pointer-events-none absolute inset-y-0 z-10 w-0.5 bg-primary/80"
      style={{ left: leftPx }}
    >
      <span className="absolute -top-px left-1/2 -translate-x-1/2 rounded-b-sm bg-primary px-1 py-0.5 text-[9px] font-medium leading-none text-primary-foreground">
        Today
      </span>
    </div>
  );
}

/* ───────── BarTooltip (Tier C, lightweight default) ───────── */

export function BarTooltip({
  item,
  statusOptions,
}: {
  item: TodoItem;
  statusOptions?: TodoStatusOption[];
}) {
  const startMs = effStartMs(item);
  const endMs = effEndMs(item);
  const statusOpt = statusOptions?.find((o) => o.value === item.status);
  return (
    <div className="min-w-44 max-w-72 space-y-1.5">
      <div className="text-xs font-semibold text-popover-foreground">
        {item.name}
      </div>
      <div className="font-mono text-[11px] text-muted-foreground">
        {endMs == null
          ? `◆ ${fmtDate(startMs)}`
          : `${fmtDate(startMs)} → ${fmtDate(endMs)}`}
      </div>
      <div className="flex items-center gap-2 pt-0.5">
        {item.targetPerson ? (
          <span className="flex items-center gap-1.5">
            <Avatar className="size-4">
              {item.targetPerson.avatar ? (
                <AvatarImage
                  src={item.targetPerson.avatar}
                  alt={item.targetPerson.name}
                />
              ) : null}
              <AvatarFallback className="text-[8px]">
                {initials(item.targetPerson.name)}
              </AvatarFallback>
            </Avatar>
            <span className="text-[11px] text-muted-foreground">
              {item.targetPerson.name}
            </span>
          </span>
        ) : null}
        {statusOpt ? (
          <Badge variant={statusOpt.variant ?? "secondary"} className="text-[10px]">
            {statusOpt.icon ? `${statusOpt.icon} ` : ""}
            {statusOpt.label}
          </Badge>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttViewport } from "../types";
import {
  addUnit,
  isWeekend,
  majorLabel,
  minorLabel,
  pickScales,
  ticks,
  x,
} from "../lib/time-scale";

const OVERSCAN_PX = 260;

/** Tier C — dumb two-tier header from a viewport. */
export function AxisHeader({
  viewport,
  bodyWidth,
  gutterWidth,
  showWeekendShading,
  className,
}: {
  viewport: GanttViewport;
  bodyWidth: number;
  gutterWidth: number;
  showWeekendShading?: boolean;
  className?: string;
}) {
  const { minor, major } = pickScales(viewport.pxPerMs);
  const fromMs = viewport.originMs - OVERSCAN_PX / viewport.pxPerMs;
  const toMs = viewport.originMs + (bodyWidth + OVERSCAN_PX) / viewport.pxPerMs;
  const ready = bodyWidth > 0;
  const minorTicks = ready ? ticks(minor, fromMs, toMs) : [];
  const majorTicks = ready ? ticks(major, fromMs, toMs) : [];
  const weekendsOn =
    showWeekendShading && (minor === "hour" || minor === "day");

  return (
    <div className={cn("flex select-none border-b bg-card", className)}>
      <div className="shrink-0 border-r border-border" style={{ width: gutterWidth }} />
      <div className="relative grow overflow-hidden" style={{ height: 46 }}>
        {weekendsOn
          ? minorTicks
              .filter((t) => isWeekend(t))
              .map((t) => {
                const left = x(viewport, t);
                const w = x(viewport, addUnit(minor, t)) - left;
                return (
                  <div
                    key={`w${t}`}
                    aria-hidden
                    className="absolute inset-y-0 bg-muted/50"
                    style={{ left, width: w }}
                  />
                );
              })
          : null}
        {majorTicks.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit(major, t)) - left;
          return (
            <div
              key={`M${t}`}
              className="absolute top-0 flex h-6 items-center overflow-hidden whitespace-nowrap border-r border-border/60 px-2 text-xs font-medium text-foreground"
              style={{ left, width: w }}
            >
              {majorLabel(major, t)}
            </div>
          );
        })}
        {minorTicks.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit(minor, t)) - left;
          return (
            <div
              key={`m${t}`}
              className="absolute bottom-0 flex h-5 items-center justify-center overflow-hidden border-r border-border/40 text-[10px] tabular-nums text-muted-foreground"
              style={{ left, width: w }}
            >
              {minorLabel(minor, t)}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/** Tier B — context-connected axis. */
export function GanttTimelineAxis({ className }: { className?: string }) {
  const { viewport, bodyWidth, gutterWidth, showWeekendShading } =
    useGanttTimeline();
  return (
    <AxisHeader
      viewport={viewport}
      bodyWidth={bodyWidth}
      gutterWidth={gutterWidth}
      showWeekendShading={showWeekendShading}
      className={className}
    />
  );
}

"use client";

/* eslint-disable react-hooks/refs -- bodyScrollRef is bundled on the context value;
   the React Compiler's refs rule false-positives on reads taken off a context object
   (see blackboard-01). Ref reads here are confined to effects + ref= props. */

import {
  useEffect,
  useRef,
  useState,
  type KeyboardEvent,
  type MouseEvent,
  type PointerEvent,
} from "react";
import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttSnap, GanttTimeUnit, GanttViewport, TodoItem } from "../types";
import {
  MS,
  addUnit,
  isWeekend,
  pickScales,
  startOfUnit,
  ticks,
  timeAt,
  x,
} from "../lib/time-scale";
import {
  BarTooltip,
  GanttBar,
  MilestoneDiamond,
  SummaryBar,
  TodayLine,
} from "./gantt-bars";
import { GanttContextMenu } from "./gantt-context-menu";

type HoverState = { item: TodoItem; leftPx: number; topPx: number };

type EditDrag =
  | {
      kind: "move";
      id: string;
      origStart: number;
      origEnd: number | null;
      grabMs: number;
      curStart: number;
      curEnd: number | null;
      topPx: number;
    }
  | {
      kind: "resize";
      id: string;
      edge: "start" | "end";
      origStart: number;
      origEnd: number;
      curStart: number;
      curEnd: number;
      topPx: number;
    }
  | {
      kind: "create";
      parentId: string | null;
      index: number;
      fromMs: number;
      toMs: number;
      topPx: number;
    }
  | {
      // v0.3.0 — group-move: rigidly shift a summary's whole subtree by deltaMs.
      kind: "groupmove";
      id: string;
      grabMs: number;
      deltaMs: number;
      spanStart: number;
      spanEnd: number;
      topPx: number;
    };

const MIN_MS = 60_000;
const DRAG_THRESHOLD = 4; // px the pointer must travel before a press becomes a gesture
const EDGE_PX = 8; // resize hot-zone at each bar edge (needs a center move zone to coexist)

/** What sits under a press — classified once on pointerdown, acted on in `resolvePending`. */
type Candidate =
  | { kind: "summary"; id: string }
  | { kind: "barEdge"; id: string; edge: "start" | "end" }
  | { kind: "barBody"; id: string }
  | { kind: "emptyRow"; rowId: string; parentId: string | null; index: number }
  | { kind: "void" };

/** A deferred press: nothing has committed yet; intent is resolved on the first move. */
type Pending = {
  pointerId: number;
  x0: number;
  y0: number;
  ms0: number;
  candidate: Candidate;
};

function snapUnitMs(snap: GanttSnap, minor: GanttTimeUnit): number {
  if (snap === "off") return 0;
  if (typeof snap === "number") return snap;
  const unit = snap === "minor" ? minor : snap;
  switch (unit) {
    case "hour":
      return MS.hour;
    case "day":
      return MS.day;
    case "week":
      return MS.week;
    case "month":
      return 2_629_800_000;
    case "quarter":
      return 7_889_400_000;
    default:
      return MS.day;
  }
}

/**
 * The calendar unit a snap setting resolves to, or null when snapping is off /
 * a fixed-ms grid. A named unit snaps to real calendar boundaries (matching the
 * axis ticks); `"minor"` follows the current minor unit (which can be month or
 * quarter when zoomed out — where average-ms rounding visibly drifts off-grid).
 */
function snapCalUnit(snap: GanttSnap, minor: GanttTimeUnit): GanttTimeUnit | null {
  if (snap === "off" || typeof snap === "number") return null;
  return snap === "minor" ? minor : snap;
}

/**
 * Snap `t` to the nearest boundary. A calendar `unit` lands on a real
 * start-of-unit (so a snapped edge lines up with a gridline the axis drew);
 * otherwise a positive `ms` grid rounds to the nearest multiple (numeric snap),
 * and `ms <= 0` with no unit means snapping is off.
 */
function snapPos(t: number, ms: number, unit: GanttTimeUnit | null): number {
  if (unit) {
    const lo = startOfUnit(unit, t);
    const hi = addUnit(unit, lo);
    return t - lo <= hi - t ? lo : hi;
  }
  return ms > 0 ? Math.round(t / ms) * ms : t;
}

const iso = (ms: number) => new Date(ms).toISOString();

export function GanttTimelineBody({ className }: { className?: string }) {
  const ctx = useGanttTimeline();
  const scrollRef = ctx.bodyScrollRef;
  const { viewport, bodyWidth, editable } = ctx;

  const [hover, setHover] = useState<HoverState | null>(null);
  const [editDrag, setEditDrag] = useState<EditDrag | null>(null);
  const editDragRef = useRef<EditDrag | null>(null);
  const pendingRef = useRef<Pending | null>(null);
  const snapUnitRef = useRef(0);
  const snapCalRef = useRef<GanttTimeUnit | null>(null);

  /* ── measure width ── */
  const setBodyWidth = ctx.setBodyWidth;
  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const update = () => setBodyWidth(el.clientWidth);
    update();
    // Coalesce observer callbacks into one rAF. We observe the same element we
    // resize, so a vertical-scrollbar appearance shrinks clientWidth → relayout →
    // re-fire; the rAF gate settles that in a single frame instead of tripping
    // the "ResizeObserver loop completed" warning.
    let raf = 0;
    const ro = new ResizeObserver(() => {
      if (raf) return;
      raf = requestAnimationFrame(() => {
        raf = 0;
        update();
      });
    });
    ro.observe(el);
    return () => {
      if (raf) cancelAnimationFrame(raf);
      ro.disconnect();
    };
  }, [scrollRef, setBodyWidth]);

  /* ── wheel (non-passive) ── */
  const { onZoomAt, onPan, disableGestures } = ctx;
  useEffect(() => {
    const el = scrollRef.current;
    if (!el || disableGestures) return;
    const onWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        setHover(null); // the bar moves under the frozen tooltip x — drop it
        const rect = el.getBoundingClientRect();
        onZoomAt(Math.exp(-e.deltaY * 0.0015), e.clientX - rect.left);
      } else if (e.shiftKey || Math.abs(e.deltaX) > Math.abs(e.deltaY)) {
        e.preventDefault();
        setHover(null);
        onPan(-(e.deltaX || e.deltaY));
      }
    };
    el.addEventListener("wheel", onWheel, { passive: false });
    return () => el.removeEventListener("wheel", onWheel);
  }, [scrollRef, disableGestures, onZoomAt, onPan]);

  /* ── pan/pinch gestures (v1) ── */
  const pointers = useRef(new Map<number, { x: number; y: number }>());
  const lockRef = useRef<null | "h" | "v">(null);
  const pinchRef = useRef<number | null>(null);
  const velRef = useRef(0);
  const lastRef = useRef<{ x: number; t: number } | null>(null);

  const { minor } = pickScales(viewport.pxPerMs);

  /** Time under the pointer (body-relative x). */
  function timeAtPointer(clientX: number, el: HTMLElement): number {
    const rect = el.getBoundingClientRect();
    return timeAt(viewport, clientX - rect.left);
  }

  /** Vertical offset (= ri.start) of an item's row — robust vs DOM nesting. */
  function rowTopOf(id: string): number {
    const ri = ctx.renderItems.find((r) => ctx.rows[r.index]?.item.id === id);
    return ri?.start ?? 0;
  }

  /* ── press classification (deferred; the gesture is chosen on the first move) ── */

  /**
   * Which edge of a bar (if any) the press is near — by PIXEL proximity to the
   * bar's geometric edges, not a DOM `[data-edge]` hit. A center move zone must
   * remain, so a narrow bar exposes no resize edges (it moves as a whole) instead
   * of being all-handle with no body to grab. Milestones / non-finite geometry
   * have no edges.
   */
  function edgeAt(
    e: PointerEvent<HTMLDivElement>,
    item: TodoItem,
  ): "start" | "end" | null {
    const geo = ctx.geometryFor(item);
    if (geo.endMs == null) return null;
    if (!Number.isFinite(geo.startMs) || !Number.isFinite(geo.endMs)) return null;
    const rect = e.currentTarget.getBoundingClientRect();
    const px = e.clientX - rect.left;
    const left = x(viewport, geo.startMs);
    const right = x(viewport, geo.endMs);
    if (right - left < EDGE_PX * 3) return null; // too narrow → whole-bar move
    if (px - left <= EDGE_PX) return "start";
    if (right - px <= EDGE_PX) return "end";
    return null;
  }

  /**
   * Classify what's under a press WITHOUT starting anything. The gesture is chosen
   * later in `resolvePending`, once the drag direction is known — so a click (no
   * movement) selects, a vertical drag scrolls, and neither is hijacked into an
   * edit. Read-only, or anything not movable/resizable, classifies as `void` → pan.
   */
  function classifyTarget(e: PointerEvent<HTMLDivElement>): Candidate {
    if (!editable) return { kind: "void" };
    const target = e.target as HTMLElement;

    // summary bracket → group-move when the whole subtree is movable; else pan.
    const summaryEl = target.closest<HTMLElement>("[data-summaryid]");
    if (summaryEl) {
      const sid = summaryEl.dataset.summaryid!;
      const sitem = ctx.getItem(sid);
      if (sitem && ctx.canGroupMove(sitem) && ctx.summarySpanFor(sitem)) {
        return { kind: "summary", id: sid };
      }
      return { kind: "void" };
    }

    // bar → resize (near a wide-enough edge) or move; else pan.
    const barEl = target.closest<HTMLElement>("[data-itemid]");
    if (barEl) {
      const id = barEl.dataset.itemid!;
      const item = ctx.rows.find((r) => r.item.id === id)?.item;
      if (item) {
        const edge = edgeAt(e, item);
        if (edge && ctx.can("resize", item)) return { kind: "barEdge", id, edge };
        if (ctx.can("move", item)) return { kind: "barBody", id };
      }
      return { kind: "void" };
    }

    // empty row area → draw a sibling, but ONLY in draw mode; otherwise pan.
    // Summary rows are derived (read-only), so they always pan.
    if (ctx.drawMode) {
      const rowEl = target.closest<HTMLElement>("[data-rowid]");
      if (rowEl) {
        const rowId = rowEl.dataset.rowid!;
        const row = ctx.rows.find((r) => r.item.id === rowId);
        if (row && !row.isSummary) {
          const info = ctx.nodeInfo(rowId);
          return {
            kind: "emptyRow",
            rowId,
            parentId: info?.parentId ?? null,
            index: (info?.index ?? 0) + 1,
          };
        }
      }
    }
    return { kind: "void" };
  }

  function moveEdit(e: PointerEvent<HTMLDivElement>) {
    const d = editDragRef.current;
    if (!d) return;
    const tMs = timeAtPointer(e.clientX, e.currentTarget);
    const u = snapUnitRef.current;
    const cu = snapCalRef.current;
    let nextDrag: EditDrag;
    if (d.kind === "move") {
      const delta = tMs - d.grabMs;
      const newStart = snapPos(d.origStart + delta, u, cu);
      const shift = newStart - d.origStart;
      nextDrag = {
        ...d,
        curStart: newStart,
        curEnd: d.origEnd != null ? d.origEnd + shift : null,
      };
    } else if (d.kind === "resize") {
      if (d.edge === "start") {
        const ns = Math.min(snapPos(tMs, u, cu), d.origEnd - MIN_MS);
        nextDrag = { ...d, curStart: ns, curEnd: d.origEnd };
      } else {
        const ne = Math.max(snapPos(tMs, u, cu), d.origStart + MIN_MS);
        nextDrag = { ...d, curStart: d.origStart, curEnd: ne };
      }
    } else if (d.kind === "groupmove") {
      // Snap the leading edge of the span; delta is the realized shift.
      const newStart = snapPos(d.spanStart + (tMs - d.grabMs), u, cu);
      nextDrag = { ...d, deltaMs: newStart - d.spanStart };
    } else {
      nextDrag = { ...d, toMs: snapPos(tMs, u, cu) };
    }
    editDragRef.current = nextDrag;
    setEditDrag(nextDrag);
  }

  function commitEdit() {
    const d = editDragRef.current;
    editDragRef.current = null;
    setEditDrag(null);
    if (!d) return;
    if (d.kind === "groupmove") {
      if (d.deltaMs !== 0) ctx.moveSubtree(d.id, d.deltaMs);
      return;
    }
    if (d.kind === "create") {
      const a = Math.min(d.fromMs, d.toMs);
      const b = Math.max(d.fromMs, d.toMs);
      if (b - a < MIN_MS) return; // a click, not a draw
      ctx.createItem(
        d.parentId,
        { startAt: iso(a), expireAt: iso(b), setAt: iso(a), name: "New task" },
        d.index,
      );
      return;
    }
    const item = ctx.rows.find((r) => r.item.id === d.id)?.item;
    if (!item) return;
    const expireDriven = item.expireAt != null;
    if (d.kind === "move") {
      if (d.curStart === d.origStart) return;
      const patch =
        expireDriven && d.curEnd != null
          ? { startAt: iso(d.curStart), expireAt: iso(d.curEnd) }
          : { startAt: iso(d.curStart) };
      ctx.rescheduleItem(d.id, patch, "move");
    } else {
      if (d.curStart === d.origStart && d.curEnd === d.origEnd) return;
      if (d.edge === "start") {
        const patch = expireDriven
          ? { startAt: iso(d.curStart) }
          : { startAt: iso(d.curStart), duration: d.origEnd - d.curStart };
        ctx.rescheduleItem(d.id, patch, "resize");
      } else {
        const patch = expireDriven
          ? { expireAt: iso(d.curEnd) }
          : { duration: d.curEnd - d.origStart };
        ctx.rescheduleItem(d.id, patch, "resize");
      }
    }
  }

  function startDrag(d: EditDrag) {
    editDragRef.current = d;
    setEditDrag(d);
  }

  /**
   * First significant move after a press picks exactly one gesture. Vertical-dominant
   * → scroll the list (edit gestures are all horizontal-intent). Horizontal-dominant
   * → the candidate decides: resize / move / group-move / draw, or pan for `void`.
   * Below the threshold the press stays pending, so a click just selects.
   */
  function resolvePending(e: PointerEvent<HTMLDivElement>) {
    const p = pendingRef.current;
    if (!p || p.pointerId !== e.pointerId) return;
    const dx = e.clientX - p.x0;
    const dy = e.clientY - p.y0;
    if (Math.hypot(dx, dy) < DRAG_THRESHOLD) return;

    pendingRef.current = null;

    // Vertical-dominant → scroll (works over bars and empty space alike).
    if (Math.abs(dy) > Math.abs(dx)) {
      lockRef.current = "v";
      lastRef.current = { x: e.clientX, t: e.timeStamp };
      return;
    }

    const c = p.candidate;
    if (c.kind === "barEdge") {
      const item = ctx.rows.find((r) => r.item.id === c.id)?.item;
      const geo = item ? ctx.geometryFor(item) : null;
      if (geo && geo.endMs != null) {
        startDrag({
          kind: "resize",
          id: c.id,
          edge: c.edge,
          origStart: geo.startMs,
          origEnd: geo.endMs,
          curStart: geo.startMs,
          curEnd: geo.endMs,
          topPx: rowTopOf(c.id),
        });
        return;
      }
    } else if (c.kind === "barBody") {
      const item = ctx.rows.find((r) => r.item.id === c.id)?.item;
      if (item) {
        const geo = ctx.geometryFor(item);
        startDrag({
          kind: "move",
          id: c.id,
          origStart: geo.startMs,
          origEnd: geo.endMs,
          grabMs: p.ms0,
          curStart: geo.startMs,
          curEnd: geo.endMs,
          topPx: rowTopOf(c.id),
        });
        return;
      }
    } else if (c.kind === "summary") {
      const sitem = ctx.getItem(c.id);
      const span = sitem ? ctx.summarySpanFor(sitem) : null;
      if (span) {
        startDrag({
          kind: "groupmove",
          id: c.id,
          grabMs: p.ms0,
          deltaMs: 0,
          spanStart: span.startMs,
          spanEnd: span.endMs,
          topPx: rowTopOf(c.id),
        });
        return;
      }
    } else if (c.kind === "emptyRow") {
      const snapped = snapPos(p.ms0, snapUnitRef.current, snapCalRef.current);
      startDrag({
        kind: "create",
        parentId: c.parentId,
        index: c.index,
        fromMs: snapped,
        toMs: snapped,
        topPx: rowTopOf(c.rowId),
      });
      return;
    }

    // void (or any fall-through) → horizontal pan.
    ctx.beginPan();
    lockRef.current = "h";
    lastRef.current = { x: e.clientX, t: e.timeStamp };
    velRef.current = 0;
  }

  function onPointerDown(e: PointerEvent<HTMLDivElement>) {
    // The context-menu content is portaled to document.body but is still a React
    // child of this scroll surface, so its pointer events bubble here through the
    // React tree. Ignore any event whose real target isn't a DOM descendant of
    // this surface, else a menu-item click would start a gesture here and swallow
    // the item's own pointerup (the "menu opens but items do nothing" bug).
    if (!e.currentTarget.contains(e.target as Node)) return;
    if (disableGestures) return;
    if (e.button === 2) return; // right-click → context menu, not a gesture

    e.currentTarget.setPointerCapture(e.pointerId);
    pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    setHover(null);
    ctx.beginPan(); // touching the canvas halts any momentum fling

    if (pointers.current.size === 2) {
      // second finger → pinch-zoom; abandon any pending or in-flight single gesture
      pendingRef.current = null;
      if (editDragRef.current) {
        editDragRef.current = null;
        setEditDrag(null);
      }
      const [a, b] = [...pointers.current.values()];
      pinchRef.current = Math.hypot(a.x - b.x, a.y - b.y);
      lockRef.current = null;
      return;
    }

    // Single pointer → DEFER. Capture snap settings + classify what's under the
    // press; the gesture itself is chosen on the first move (`resolvePending`).
    snapUnitRef.current = e.altKey ? 0 : snapUnitMs(ctx.snap, minor);
    snapCalRef.current = e.altKey ? null : snapCalUnit(ctx.snap, minor);
    pendingRef.current = {
      pointerId: e.pointerId,
      x0: e.clientX,
      y0: e.clientY,
      ms0: timeAtPointer(e.clientX, e.currentTarget),
      candidate: classifyTarget(e),
    };
    lockRef.current = null;
    lastRef.current = null;
    velRef.current = 0;
  }

  function onPointerMove(e: PointerEvent<HTMLDivElement>) {
    if (editDragRef.current) {
      moveEdit(e);
      return;
    }
    if (disableGestures) return;

    // pinch-zoom (two active pointers)
    if (pointers.current.size >= 2 && pinchRef.current != null) {
      pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
      const [a, b] = [...pointers.current.values()];
      const dist = Math.hypot(a.x - b.x, a.y - b.y);
      if (dist > 0 && pinchRef.current > 0) {
        const rect = e.currentTarget.getBoundingClientRect();
        onZoomAt(dist / pinchRef.current, (a.x + b.x) / 2 - rect.left);
      }
      pinchRef.current = dist;
      return;
    }

    // a press is still pending → update its position and try to resolve intent
    if (pendingRef.current && pendingRef.current.pointerId === e.pointerId) {
      pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
      resolvePending(e);
      return;
    }

    // resolved pan / vertical-scroll
    const prev = pointers.current.get(e.pointerId);
    if (!prev) return;
    const dx = e.clientX - prev.x;
    const dy = e.clientY - prev.y;
    pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    if (lockRef.current === "h") {
      onPan(dx);
      const last = lastRef.current;
      const t = e.timeStamp;
      if (last && t > last.t) velRef.current = (e.clientX - last.x) / (t - last.t);
      lastRef.current = { x: e.clientX, t };
    } else if (lockRef.current === "v" && e.pointerType === "mouse") {
      const el = scrollRef.current;
      if (el) el.scrollTop -= dy;
    }
  }

  function endPointer(e: PointerEvent<HTMLDivElement>) {
    const wasEdit = editDragRef.current != null;
    if (wasEdit) commitEdit();
    pendingRef.current = null; // never crossed threshold → a click; onClick handles select

    if (pointers.current.has(e.pointerId)) pointers.current.delete(e.pointerId);
    if (pointers.current.size < 2) pinchRef.current = null;

    if (!wasEdit && pointers.current.size === 0 && lockRef.current === "h") {
      const last = lastRef.current;
      const fresh = last != null && e.timeStamp - last.t <= 100;
      ctx.endPanWithVelocity(fresh ? velRef.current : 0);
    }
    if (pointers.current.size === 0) {
      lockRef.current = null;
      lastRef.current = null;
    }
  }

  /* ── keyboard editing (body-focused + a selected item) ── */
  function onKeyDown(e: KeyboardEvent<HTMLDivElement>) {
    // Ignore keys bubbling from the portaled context menu (see onPointerDown) so
    // menu navigation/select doesn't double-trigger body reschedule/delete/open.
    if (!e.currentTarget.contains(e.target as Node)) return;
    if (!editable || !ctx.selectedId) return;
    const item = ctx.rows.find((r) => r.item.id === ctx.selectedId)?.item;
    if (!item) return;
    const u = snapUnitMs(ctx.snap, minor) || MS.day;
    const geo = ctx.geometryFor(item);
    const expireDriven = item.expireAt != null;
    switch (e.key) {
      case "Delete":
      case "Backspace":
        e.preventDefault();
        ctx.deleteItem(item.id);
        break;
      case "Enter":
        e.preventDefault();
        ctx.openEditor(item.id);
        break;
      case "ArrowLeft":
      case "ArrowRight": {
        e.preventDefault();
        if (
          !Number.isFinite(geo.startMs) ||
          (geo.endMs != null && !Number.isFinite(geo.endMs))
        )
          break; // unparseable date — skip keyboard reschedule (Delete/Enter still work)
        const dir = e.key === "ArrowRight" ? 1 : -1;
        if (e.shiftKey && geo.endMs != null) {
          const ne = Math.max(geo.startMs + MIN_MS, geo.endMs + dir * u);
          ctx.rescheduleItem(
            item.id,
            expireDriven
              ? { expireAt: iso(ne) }
              : { duration: ne - geo.startMs },
            "resize",
          );
        } else {
          const ns = geo.startMs + dir * u;
          ctx.rescheduleItem(
            item.id,
            expireDriven && geo.endMs != null
              ? { startAt: iso(ns), expireAt: iso(geo.endMs + dir * u) }
              : { startAt: iso(ns) },
            "move",
          );
        }
        break;
      }
      default:
        break;
    }
  }

  /**
   * v0.5.0 — double-click an empty row area → quick-create a sibling task at that
   * time. A double-click ON a bar/summary opens the editor (handled on the shape),
   * so ignore those targets here. Independent of draw mode (draw = drag a span).
   */
  function onDoubleClick(e: MouseEvent<HTMLDivElement>) {
    if (!editable) return;
    const target = e.target as HTMLElement;
    if (target.closest("[data-itemid]") || target.closest("[data-summaryid]"))
      return;
    const rowEl = target.closest<HTMLElement>("[data-rowid]");
    if (!rowEl) return;
    const rowId = rowEl.dataset.rowid!;
    const row = ctx.rows.find((r) => r.item.id === rowId);
    if (!row || row.isSummary) return;
    const info = ctx.nodeInfo(rowId);
    const startMs = snapPos(
      timeAtPointer(e.clientX, e.currentTarget),
      snapUnitMs(ctx.snap, minor),
      snapCalUnit(ctx.snap, minor),
    );
    const span = snapUnitMs(ctx.snap, minor) || MS.day;
    const composerTarget = {
      startMs,
      endMs: startMs + span,
      parentId: info?.parentId ?? null,
      index: (info?.index ?? 0) + 1,
      x: e.clientX,
      y: e.clientY,
    };
    if (ctx.quickCompose) {
      ctx.openComposer(composerTarget);
    } else {
      ctx.createItem(
        composerTarget.parentId,
        {
          name: "New task",
          startAt: iso(startMs),
          expireAt: iso(startMs + span),
          setAt: iso(startMs),
        },
        composerTarget.index,
        { openEditor: true },
      );
    }
  }

  /* ── weekend bands ── */
  const weekendsOn =
    ctx.showWeekendShading && (minor === "hour" || minor === "day");
  const dayBands =
    weekendsOn && bodyWidth > 0
      ? ticks(
          "day",
          viewport.originMs - 86_400_000,
          viewport.originMs + bodyWidth / viewport.pxPerMs,
        ).filter(isWeekend)
      : [];

  const todayLeft = x(viewport, ctx.nowMs);
  const showToday =
    ctx.showTodayLine && todayLeft >= -2 && todayLeft <= bodyWidth + 2;

  function activate(item: TodoItem) {
    ctx.setFocusedId(item.id);
    ctx.select(item.id);
    ctx.onTaskClick?.(item);
    scrollRef.current?.focus();
  }

  return (
    <div
      ref={scrollRef}
      tabIndex={editable ? 0 : undefined}
      onScroll={(e) => ctx.onBodyScroll(e.currentTarget.scrollTop)}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={endPointer}
      onPointerCancel={endPointer}
      onDoubleClick={onDoubleClick}
      onKeyDown={onKeyDown}
      style={{ touchAction: disableGestures ? undefined : "pan-y" }}
      className={cn(
        "relative h-full grow overflow-x-hidden overflow-y-auto bg-background outline-none",
        !disableGestures &&
          !editDrag &&
          !(editable && ctx.drawMode) &&
          "cursor-grab active:cursor-grabbing",
        (editDrag?.kind === "create" || (editable && ctx.drawMode)) &&
          "cursor-crosshair",
        className,
      )}
    >
      <div className="relative" style={{ height: ctx.totalSize, minWidth: "100%" }}>
        {dayBands.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit("day", t)) - left;
          return (
            <div
              key={`wk${t}`}
              aria-hidden
              className="absolute inset-y-0 bg-muted/40"
              style={{ left, width: w }}
            />
          );
        })}

        {showToday ? <TodayLine leftPx={todayLeft} /> : null}

        {ctx.renderItems.map((ri) => {
          const row = ctx.rows[ri.index];
          if (!row) return null;
          const item = row.item;
          const selected = ctx.selectedId === item.id;
          const color = ctx.resolveColor(item);
          const geo = ctx.geometryFor(item);
          const priColor = item.priority
            ? ctx.priorityOptions?.find((o) => o.value === item.priority)?.color
            : undefined;
          const movable = editable && ctx.can("move", item);
          const resizable = editable && ctx.can("resize", item);

          const enter = (leftPx: number) =>
            setHover({ item, leftPx, topPx: ri.start });
          const leave = () => setHover(null);

          // A bad/unparseable date yields NaN geometry. Render no shape (the row
          // label still shows) so we never position a bar at NaN→origin or throw
          // on a later edit-commit. Summary rows use summarySpan, which is NaN-safe.
          const geoOk =
            Number.isFinite(geo.startMs) &&
            (geo.endMs == null || Number.isFinite(geo.endMs));

          let shape: React.ReactNode = null;
          let labelLeft = 0;

          if (row.isSummary) {
            const span = ctx.summarySpanFor(item);
            if (span) {
              const left = x(viewport, span.startMs);
              const w = x(viewport, span.endMs) - left;
              labelLeft = left + Math.max(w, 8) + 6;
              shape = (
                <SummaryBar
                  data-summaryid={item.id}
                  leftPx={left}
                  widthPx={w}
                  selected={selected}
                  groupMovable={editable && ctx.canGroupMove(item)}
                  aria-hidden
                  onClick={() => activate(item)}
                  onMouseEnter={() => enter(left)}
                  onMouseLeave={leave}
                />
              );
            }
          } else if (!geoOk) {
            // unparseable date — label-only row, no draggable bar (see geoOk note)
          } else if (geo.isMilestone) {
            const left = x(viewport, geo.startMs);
            labelLeft = left + 10;
            shape = (
              <MilestoneDiamond
                data-itemid={item.id}
                leftPx={left}
                fill={color.fill}
                selected={selected}
                movable={movable}
                aria-hidden
                onClick={() => activate(item)}
                onDoubleClick={() => editable && ctx.openEditor(item.id)}
                onMouseEnter={() => enter(left)}
                onMouseLeave={leave}
              />
            );
          } else if (geo.endMs != null) {
            const left = x(viewport, geo.startMs);
            const w = x(viewport, geo.endMs) - left;
            labelLeft = left + Math.max(w, 6) + 6;
            shape = (
              <GanttBar
                data-itemid={item.id}
                leftPx={left}
                widthPx={w}
                fill={color.fill}
                rowHeight={ctx.rowHeight}
                overdue={color.isOverdue}
                inactive={!item.active}
                locked={item.locked}
                priorityColor={priColor}
                selected={selected}
                movable={movable}
                resizable={resizable}
                aria-hidden
                onClick={() => activate(item)}
                onDoubleClick={() => editable && ctx.openEditor(item.id)}
                onMouseEnter={() => enter(left)}
                onMouseLeave={leave}
              />
            );
          }

          const rowInner = (
            <div
              data-rowid={item.id}
              className={cn(
                "absolute inset-x-0 border-b border-border/40",
                selected && "bg-accent/40",
              )}
              style={{ top: ri.start, height: ctx.rowHeight }}
            >
              {shape}
              {labelLeft < bodyWidth + 40 ? (
                <span
                  className={cn(
                    "pointer-events-none absolute top-1/2 max-w-55 -translate-y-1/2 truncate text-xs",
                    row.isSummary
                      ? "font-medium text-foreground"
                      : "text-foreground/85",
                  )}
                  style={{ left: labelLeft }}
                >
                  {item.name}
                </span>
              ) : null}
            </div>
          );

          return editable && !row.isSummary ? (
            <GanttContextMenu key={item.id} item={item}>
              {rowInner}
            </GanttContextMenu>
          ) : (
            <div key={item.id}>{rowInner}</div>
          );
        })}

        {/* edit drag preview */}
        {editDrag ? (
          <EditPreview
            drag={editDrag}
            viewport={viewport}
            rowHeight={ctx.rowHeight}
          />
        ) : null}

        {hover && !editDrag ? (
          <div
            className="pointer-events-none absolute z-30 rounded-md border border-border bg-popover p-2.5 text-popover-foreground shadow-md"
            style={{
              left: Math.max(
                4,
                Math.min(hover.leftPx, Math.max(4, bodyWidth - 200)),
              ),
              top:
                hover.topPx > 96 ? hover.topPx - 8 : hover.topPx + ctx.rowHeight + 6,
              transform: hover.topPx > 96 ? "translateY(-100%)" : undefined,
            }}
          >
            {ctx.renderTooltip?.(hover.item) ?? (
              <BarTooltip item={hover.item} statusOptions={ctx.statusOptions} />
            )}
          </div>
        ) : null}
      </div>
    </div>
  );

}

function EditPreview({
  drag,
  viewport,
  rowHeight,
}: {
  drag: EditDrag;
  viewport: GanttViewport;
  rowHeight: number;
}) {
  let left: number;
  let width: number;
  let label: string;
  if (drag.kind === "create") {
    const a = Math.min(drag.fromMs, drag.toMs);
    const b = Math.max(drag.fromMs, drag.toMs);
    left = x(viewport, a);
    width = Math.max(x(viewport, b) - left, 2);
    label = `${new Date(a).toLocaleDateString()} → ${new Date(b).toLocaleDateString()}`;
  } else if (drag.kind === "groupmove") {
    const s = drag.spanStart + drag.deltaMs;
    const e = drag.spanEnd + drag.deltaMs;
    left = x(viewport, s);
    width = Math.max(x(viewport, e) - left, 8);
    label = `${new Date(s).toLocaleDateString()} → ${new Date(e).toLocaleDateString()}`;
  } else {
    const start = drag.curStart;
    const end = drag.curEnd ?? drag.curStart;
    left = x(viewport, start);
    width = Math.max(x(viewport, end) - left, 6);
    label =
      drag.curEnd == null
        ? new Date(start).toLocaleDateString()
        : `${new Date(start).toLocaleDateString()} → ${new Date(end).toLocaleDateString()}`;
  }
  return (
    <div
      aria-hidden
      className="pointer-events-none absolute z-40"
      style={{ top: drag.topPx, height: rowHeight }}
    >
      <div
        className="absolute top-1/2 h-5 -translate-y-1/2 rounded-[5px] border-2 border-primary bg-primary/20"
        style={{ left, width }}
      />
      <span
        className="absolute top-1/2 -translate-y-1/2 whitespace-nowrap rounded bg-primary px-1.5 py-0.5 font-mono text-[10px] leading-none text-primary-foreground"
        style={{ left: left + width + 6 }}
      >
        {label}
      </span>
    </div>
  );
}

"use client";

/* eslint-disable react-hooks/refs -- gutterTrackRef is bundled on the context value; the
   React Compiler's refs rule false-positives on reads taken off a context object (see
   blackboard-01). The ref is used only as a ref= prop + read inside effects. */

import { useEffect, useRef, type KeyboardEvent } from "react";
import {
  DndContext,
  KeyboardSensor,
  PointerSensor,
  pointerWithin,
  useDraggable,
  useDroppable,
  useSensor,
  useSensors,
  type DragEndEvent,
} from "@dnd-kit/core";
import { ChevronRight, GripVertical, Plus, Trash2 } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttRow, TodoLabelOption, TodoStatusOption } from "../types";
import { effEndMs, effStartMs } from "../lib/geometry";
import { GanttContextMenu } from "./gantt-context-menu";

function initials(name: string): string {
  return name
    .split(/\s+/)
    .map((p) => p[0])
    .filter(Boolean)
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

function rowAriaLabel(row: GanttRow, statusOpt?: TodoStatusOption): string {
  const { item } = row;
  const start = new Date(effStartMs(item)).toLocaleDateString();
  const end = effEndMs(item);
  const when =
    end == null
      ? `milestone ${start}`
      : `${start} to ${new Date(end).toLocaleDateString()}`;
  const status = statusOpt ? `, ${statusOpt.label}` : "";
  return `${item.name}, ${when}${status}`;
}

/* ───────── GutterRow (Tier C) ───────── */

export function GutterRow({
  row,
  statusOptions,
  labelOptions,
  selected,
  tabIndex,
  onToggle,
  onActivate,
  editable,
  renaming,
  canCreate,
  canDelete,
  gripRef,
  gripProps,
  onAddChild,
  onDelete,
  onRenameCommit,
  onRenameCancel,
}: {
  row: GanttRow;
  statusOptions?: TodoStatusOption[];
  labelOptions?: TodoLabelOption[];
  selected?: boolean;
  tabIndex: number;
  onToggle: () => void;
  onActivate: () => void;
  editable?: boolean;
  renaming?: boolean;
  canCreate?: boolean;
  canDelete?: boolean;
  gripRef?: (el: HTMLElement | null) => void;
  gripProps?: Record<string, unknown>;
  onAddChild?: () => void;
  onDelete?: () => void;
  onRenameCommit?: (name: string) => void;
  onRenameCancel?: () => void;
}) {
  const { item, depth, hasChildren, collapsed, posInSet, setSize } = row;
  const statusOpt = statusOptions?.find((o) => o.value === item.status);
  const dots = (item.labels ?? [])
    .map((key) => labelOptions?.find((o) => o.value === key))
    .filter(Boolean)
    .slice(0, 4) as TodoLabelOption[];

  return (
    <div
      role="treeitem"
      aria-level={depth + 1}
      aria-setsize={setSize}
      aria-posinset={posInSet}
      aria-expanded={hasChildren ? !collapsed : undefined}
      aria-selected={selected || undefined}
      aria-label={rowAriaLabel(row, statusOpt)}
      data-rowid={item.id}
      tabIndex={tabIndex}
      onClick={onActivate}
      className={cn(
        "group/row flex h-full cursor-default select-none items-center gap-1.5 border-b border-border/40 pr-2 outline-none",
        "focus-visible:bg-accent focus-visible:ring-1 focus-visible:ring-inset focus-visible:ring-ring",
        selected && "bg-accent",
        !item.active && "opacity-60",
      )}
      style={{ paddingLeft: 8 + depth * 16 }}
    >
      {editable ? (
        <button
          ref={gripRef as ((el: HTMLButtonElement | null) => void) | undefined}
          type="button"
          tabIndex={-1}
          aria-label="Drag to reorder"
          onClick={(e) => e.stopPropagation()}
          className="-ml-1 hidden shrink-0 cursor-grab touch-none text-muted-foreground hover:text-foreground active:cursor-grabbing group-hover/row:block"
          {...gripProps}
        >
          <GripVertical className="size-3.5" />
        </button>
      ) : null}

      {hasChildren ? (
        <button
          type="button"
          tabIndex={-1}
          aria-label={collapsed ? "Expand" : "Collapse"}
          onClick={(e) => {
            e.stopPropagation();
            onToggle();
          }}
          className="grid size-4 shrink-0 place-items-center rounded text-muted-foreground hover:bg-muted hover:text-foreground"
        >
          <ChevronRight
            className={cn(
              "size-3.5 transition-transform",
              !collapsed && "rotate-90",
            )}
          />
        </button>
      ) : (
        <span className="inline-block w-4 shrink-0" />
      )}

      {item.targetPerson ? (
        <Avatar className="size-5 shrink-0">
          {item.targetPerson.avatar ? (
            <AvatarImage
              src={item.targetPerson.avatar}
              alt={item.targetPerson.name}
            />
          ) : null}
          <AvatarFallback className="text-[9px]">
            {initials(item.targetPerson.name)}
          </AvatarFallback>
        </Avatar>
      ) : null}

      {renaming ? (
        <Input
          autoFocus
          defaultValue={item.name}
          onClick={(e) => e.stopPropagation()}
          onKeyDown={(e) => {
            e.stopPropagation();
            if (e.key === "Enter") onRenameCommit?.(e.currentTarget.value.trim());
            else if (e.key === "Escape") onRenameCancel?.();
          }}
          onBlur={(e) => onRenameCommit?.(e.currentTarget.value.trim())}
          className="h-6 flex-1 px-1.5 py-0 text-sm"
        />
      ) : (
        <span className="truncate text-sm text-foreground">{item.name}</span>
      )}

      {!renaming && dots.length > 0 ? (
        <span className="ml-auto flex shrink-0 items-center gap-1">
          {dots.map((d) => (
            <span
              key={d.value}
              title={d.label}
              className="size-2 rounded-full"
              style={{ background: d.color ?? "var(--muted-foreground)" }}
            />
          ))}
        </span>
      ) : null}

      {!renaming && statusOpt ? (
        <Badge
          variant={statusOpt.variant ?? "secondary"}
          className={cn("shrink-0 text-[10px]", dots.length === 0 && "ml-auto")}
        >
          {statusOpt.label}
        </Badge>
      ) : null}

      {editable && !renaming ? (
        <span className="hidden shrink-0 items-center gap-0.5 group-hover/row:flex">
          {canCreate ? (
            <button
              type="button"
              tabIndex={-1}
              aria-label="Add child task"
              onClick={(e) => {
                e.stopPropagation();
                onAddChild?.();
              }}
              className="grid size-5 place-items-center rounded text-muted-foreground hover:bg-muted hover:text-foreground"
            >
              <Plus className="size-3.5" />
            </button>
          ) : null}
          {canDelete ? (
            <button
              type="button"
              tabIndex={-1}
              aria-label="Delete task"
              onClick={(e) => {
                e.stopPropagation();
                onDelete?.();
              }}
              className="grid size-5 place-items-center rounded text-muted-foreground hover:bg-destructive/15 hover:text-destructive"
            >
              <Trash2 className="size-3.5" />
            </button>
          ) : null}
        </span>
      ) : null}
    </div>
  );
}

/* ───────── drop zones (Tier-B internal) ───────── */

function DropZones({ id }: { id: string }) {
  const before = useDroppable({ id: `before:${id}` });
  const into = useDroppable({ id: `into:${id}` });
  const after = useDroppable({ id: `after:${id}` });
  return (
    <>
      <div
        ref={before.setNodeRef}
        className={cn(
          "pointer-events-none absolute inset-x-0 top-0 h-1/4",
          before.isOver && "border-t-2 border-primary",
        )}
      />
      <div
        ref={into.setNodeRef}
        className={cn(
          "pointer-events-none absolute inset-x-0 top-1/4 h-2/4",
          into.isOver && "rounded bg-primary/15 ring-1 ring-inset ring-primary",
        )}
      />
      <div
        ref={after.setNodeRef}
        className={cn(
          "pointer-events-none absolute inset-x-0 bottom-0 h-1/4",
          after.isOver && "border-b-2 border-primary",
        )}
      />
    </>
  );
}

/* ───────── GanttTimelineGutter (Tier B) ───────── */

export function GanttTimelineGutter({ className }: { className?: string }) {
  const ctx = useGanttTimeline();
  const treeRef = useRef<HTMLDivElement | null>(null);
  // Alias the bundled ref object to a local so the compiler tracks it as a
  // RefObject (mutating `.current.scrollTop` is then a legal ref mutation, not a
  // forbidden modification of a context value — same pattern as the body).
  const bodyScrollRef = ctx.bodyScrollRef;

  const rows = ctx.rows;
  // Refs so the focus effect can read the latest rows/rowHeight without widening
  // its dependency to "any data change" (which would steal focus on every edit).
  const rowsRef = useRef(rows);
  rowsRef.current = rows;
  const rowHeightRef = useRef(ctx.rowHeight);
  rowHeightRef.current = ctx.rowHeight;
  const activeId = ctx.focusedId ?? rows[0]?.item.id ?? null;

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 4 } }),
    useSensor(KeyboardSensor),
  );

  // Move DOM focus to the focused row. A virtualized row outside the scroll
  // window isn't in the DOM, so we first scroll the body to bring it into view
  // (the gutter mirrors body scroll via translateY) — otherwise focus() would
  // no-op and keyboard nav would silently dead-end past the visible rows. The
  // body re-renders the row asynchronously after the scroll, so retry across a
  // few frames until the node exists.
  useEffect(() => {
    const fid = ctx.focusedId;
    const track = treeRef.current;
    if (!fid || !track) return;

    const idx = rowsRef.current.findIndex((r) => r.item.id === fid);
    const el = bodyScrollRef.current;
    const rh = rowHeightRef.current;
    if (idx >= 0 && el) {
      const top = idx * rh;
      const bottom = top + rh;
      if (top < el.scrollTop) el.scrollTop = top;
      else if (bottom > el.scrollTop + el.clientHeight)
        el.scrollTop = bottom - el.clientHeight;
    }

    const safe =
      typeof CSS !== "undefined" && CSS.escape
        ? CSS.escape(fid)
        : fid.replace(/"/g, '\\"');
    let raf = 0;
    let tries = 0;
    const focusRow = () => {
      const node = track.querySelector<HTMLElement>(`[data-rowid="${safe}"]`);
      if (node) node.focus();
      else if (tries++ < 3) raf = requestAnimationFrame(focusRow);
    };
    focusRow();
    return () => {
      if (raf) cancelAnimationFrame(raf);
    };
  }, [ctx.focusedId, bodyScrollRef]);

  function onKeyDown(e: KeyboardEvent<HTMLDivElement>) {
    // The context menu portals its content but is still a React child of this
    // tree, so its keydowns bubble here. Ignore events that didn't originate
    // inside the tree, else menu navigation double-triggers row nav/select/delete.
    if (!e.currentTarget.contains(e.target as Node)) return;
    if (ctx.renamingId) return; // rename input owns the keys
    const i = rows.findIndex((r) => r.item.id === activeId);
    const focusAt = (j: number) => {
      const r = rows[Math.max(0, Math.min(rows.length - 1, j))];
      if (r) ctx.setFocusedId(r.item.id);
    };
    const cur = rows[i];
    switch (e.key) {
      case "ArrowDown":
        e.preventDefault();
        focusAt(i + 1);
        break;
      case "ArrowUp":
        e.preventDefault();
        focusAt(i - 1);
        break;
      case "Home":
        e.preventDefault();
        focusAt(0);
        break;
      case "End":
        e.preventDefault();
        focusAt(rows.length - 1);
        break;
      case "ArrowRight":
        if (cur?.hasChildren && cur.collapsed) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        } else if (i < rows.length - 1) {
          e.preventDefault();
          focusAt(i + 1);
        }
        break;
      case "ArrowLeft":
        if (cur?.hasChildren && !cur.collapsed) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        } else if (cur?.parentId) {
          e.preventDefault();
          ctx.setFocusedId(cur.parentId);
        }
        break;
      case "Enter":
        if (cur) {
          e.preventDefault();
          ctx.select(cur.item.id);
          ctx.onTaskClick?.(cur.item);
        }
        break;
      case "F2":
        if (cur && ctx.editable) {
          e.preventDefault();
          ctx.beginRename(cur.item.id);
        }
        break;
      case "Delete":
      case "Backspace":
        if (cur && ctx.editable) {
          e.preventDefault();
          ctx.deleteItem(cur.item.id);
        }
        break;
      case " ":
        if (cur?.hasChildren) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        }
        break;
      default:
        break;
    }
  }

  function onDragEnd(e: DragEndEvent) {
    const activeId = String(e.active.id);
    if (!e.over) return;
    const [zone, targetId] = String(e.over.id).split(":");
    if (!targetId || targetId === activeId) return;
    const info = ctx.nodeInfo(targetId);
    if (zone === "into") {
      const target = ctx.getItem(targetId);
      ctx.moveItemAction(activeId, targetId, target?.children?.length ?? 0);
    } else if (zone === "before") {
      ctx.moveItemAction(activeId, info?.parentId ?? null, info?.index ?? 0);
    } else {
      ctx.moveItemAction(activeId, info?.parentId ?? null, (info?.index ?? 0) + 1);
    }
  }

  const tree = (
    <div
      ref={treeRef}
      role="tree"
      aria-label="Task rows"
      onKeyDown={onKeyDown}
      className={cn(
        "h-full shrink-0 overflow-hidden border-r border-border bg-card",
        className,
      )}
      style={{ width: ctx.gutterWidth }}
    >
      <div
        ref={ctx.gutterTrackRef}
        className="relative"
        style={{ height: ctx.totalSize }}
      >
        {ctx.renderItems.map((ri) => {
          const row = rows[ri.index];
          if (!row) return null;
          return (
            <GutterRowItem
              key={row.item.id}
              row={row}
              top={ri.start}
              height={ctx.rowHeight}
              activeId={activeId}
            />
          );
        })}
      </div>
    </div>
  );

  // A single DndContext is always present (draggables self-disable when read-only)
  // so the per-row `useDraggable` hooks always have a provider.
  return (
    <DndContext
      sensors={sensors}
      collisionDetection={pointerWithin}
      onDragEnd={onDragEnd}
    >
      {tree}
    </DndContext>
  );
}

/** One gutter row: drag source (grip activator) + drop zones + the dumb GutterRow. */
function GutterRowItem({
  row,
  top,
  height,
  activeId,
}: {
  row: GanttRow;
  top: number;
  height: number;
  activeId: string | null;
}) {
  const ctx = useGanttTimeline();
  const id = row.item.id;
  const item = row.item;
  const canMove = ctx.editable && ctx.can("move", item);
  const canCreate = ctx.editable && ctx.can("create", item);
  const canDelete = ctx.editable && ctx.can("delete", item);
  const draggable = useDraggable({ id, disabled: !canMove });

  return (
    <div
      ref={draggable.setNodeRef}
      className={cn("absolute inset-x-0", draggable.isDragging && "opacity-40")}
      style={{ top, height }}
    >
      <GanttContextMenu item={item}>
        <GutterRow
          row={row}
          statusOptions={ctx.statusOptions}
          labelOptions={ctx.labelOptions}
          selected={ctx.selectedId === id}
          tabIndex={activeId === id ? 0 : -1}
          editable={ctx.editable}
          renaming={ctx.renamingId === id}
          canCreate={canCreate}
          canDelete={canDelete}
          gripRef={canMove ? draggable.setActivatorNodeRef : undefined}
          gripProps={
            canMove ? { ...draggable.listeners, ...draggable.attributes } : undefined
          }
          onToggle={() => ctx.toggleCollapse(id)}
          onActivate={() => {
            ctx.setFocusedId(id);
            ctx.select(id);
            ctx.onTaskClick?.(item);
          }}
          onAddChild={() => ctx.createItem(id)}
          onDelete={() => ctx.deleteItem(id)}
          onRenameCommit={(name) => {
            if (name) ctx.renameItemAction(id, name);
            ctx.endRename();
          }}
          onRenameCancel={() => ctx.endRename()}
        />
      </GanttContextMenu>
      {ctx.editable ? <DropZones id={id} /> : null}
    </div>
  );
}

"use client";

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import type {
  GanttColorResolver,
  GanttContextValue,
  GanttTimelineHandle,
  GanttTimelineRootProps,
  TodoItem,
} from "../types";
import {
  dataExtent as computeExtent,
  effStartMs,
  geometryFor as computeGeometry,
  summarySpan,
} from "../lib/geometry";
import { ancestorsOf, flatten, indexById, parentIds } from "../lib/flatten";
import { barFill, resolveRamp, toneFor } from "../lib/color";
import { useColorTick } from "../hooks/use-color-tick";
import { useGanttViewport } from "../hooks/use-gantt-viewport";
import { useGanttVirtual } from "../hooks/use-gantt-virtual";
import { useGanttEdit } from "../hooks/use-gantt-edit";
import { GanttContext } from "../hooks/use-gantt-context";
import { GanttEditPopover } from "./gantt-edit-popover";
import { GanttQuickComposer } from "./gantt-quick-composer";
import {
  readTasksFromClipboardEvent,
  writeTasksToClipboardEvent,
} from "../../todo-rich-card/lib/clipboard";

export const GanttTimelineRoot = forwardRef<
  GanttTimelineHandle,
  GanttTimelineRootProps
>(function GanttTimelineRoot(props, ref) {
  const {
    data,
    statusOptions,
    priorityOptions,
    labelOptions,
    colorRamp,
    colorRefreshIntervalMs = 60_000,
    zoom,
    defaultZoom = "week",
    onZoomChange,
    minZoom = "hour",
    maxZoom = "quarter",
    onViewportChange,
    disableGestures = false,
    range,
    now,
    rowHeight = 36,
    gutterWidth = 280,
    showWeekendShading = false,
    defaultCollapsedIds,
    collapsedIds,
    onCollapsedChange,
    selectedId,
    onSelect,
    onTaskClick,
    renderTooltip,
    // editing (v0.2.0)
    editable = false,
    onChange,
    snap = "minor",
    quickCompose = true,
    renderQuickComposer,
    onTaskReschedule,
    onItemAdded,
    onItemRemoved,
    onItemMoved,
    onFieldEdited,
    onStatusChanged,
    permissions,
    canMoveItem,
    canResizeItem,
    canDeleteItem,
    canCreateChild,
    canEditItem,
    onPermissionDenied,
    className,
    children,
  } = props;
  const ariaLabel = props["aria-label"];

  /* ── now (SSR-safe) ── */
  const tick = useColorTick(colorRefreshIntervalMs);
  const [clientNow, setClientNow] = useState<number | null>(null);
  useEffect(() => {
    if (now == null) setClientNow(Date.now());
  }, [now, tick]);
  const resolvedNow = now != null ? (typeof now === "function" ? now() : now) : null;

  const extent = useMemo(() => computeExtent(data), [data]);
  const nowMs =
    resolvedNow != null ? resolvedNow.getTime() : clientNow ?? extent.startMs;
  const showTodayLine = resolvedNow != null || clientNow != null;

  /* ── collapse (controlled / uncontrolled) ── */
  const collapseControlled = collapsedIds != null;
  const [internalCollapsed, setInternalCollapsed] = useState<Set<string>>(
    () => new Set(defaultCollapsedIds ?? []),
  );
  const collapsedSet = useMemo(
    () => (collapseControlled ? new Set(collapsedIds) : internalCollapsed),
    [collapseControlled, collapsedIds, internalCollapsed],
  );
  const setCollapsed = useCallback(
    (next: Set<string>) => {
      if (!collapseControlled) setInternalCollapsed(next);
      onCollapsedChange?.([...next]);
    },
    [collapseControlled, onCollapsedChange],
  );
  const isCollapsed = useCallback((id: string) => collapsedSet.has(id), [collapsedSet]);
  const toggleCollapse = useCallback(
    (id: string) => {
      const next = new Set(collapsedSet);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setCollapsed(next);
    },
    [collapsedSet, setCollapsed],
  );

  /* ── selection (controlled / uncontrolled) ── */
  const selControlled = selectedId !== undefined;
  const [internalSel, setInternalSel] = useState<string | null>(null);
  const selectedVal = selControlled ? selectedId ?? null : internalSel;
  const select = useCallback(
    (id: string | null) => {
      if (!selControlled) setInternalSel(id);
      onSelect?.(id);
    },
    [selControlled, onSelect],
  );

  const [focusedId, setFocusedId] = useState<string | null>(null);

  /* ── draw mode (v0.4.0) — empty-row drag draws vs pans; toolbar-toggled ── */
  const [drawMode, setDrawMode] = useState(false);

  /* ── rows + virtualization ── */
  const rows = useMemo(() => flatten(data, (id) => collapsedSet.has(id)), [data, collapsedSet]);
  const rowsRef = useRef(rows);
  rowsRef.current = rows;
  const itemIndex = useMemo(() => indexById(data), [data]);

  const bodyScrollRef = useRef<HTMLDivElement | null>(null);
  const gutterTrackRef = useRef<HTMLDivElement | null>(null);
  const rootRef = useRef<HTMLDivElement | null>(null);
  const { renderItems, totalSize } = useGanttVirtual({
    count: rows.length,
    scrollRef: bodyScrollRef,
    rowHeight,
  });

  const [bodyWidth, setBodyWidth] = useState(0);

  /* ── viewport ── */
  const vp = useGanttViewport({
    dataExtent: extent,
    bodyWidth,
    defaultZoom,
    controlledZoom: zoom,
    onZoomChange,
    minZoom,
    maxZoom,
    onViewportChange,
    range,
    nowMs,
  });

  /* ── color + geometry closures ── */
  const ramp = useMemo(() => resolveRamp(colorRamp), [colorRamp]);
  const geometryFor = useCallback(
    (item: TodoItem) => computeGeometry(item, nowMs, toneFor(item, statusOptions)),
    [nowMs, statusOptions],
  );
  const resolveColor = useCallback<GanttColorResolver>(
    (item) => {
      const { fill, tone } = barFill(item, nowMs, ramp, statusOptions);
      return { fill, tone, isOverdue: geometryFor(item).isOverdue };
    },
    [nowMs, ramp, statusOptions, geometryFor],
  );
  const summarySpanFor = useCallback(
    (item: TodoItem) => summarySpan(item),
    [],
  );

  /* ── editing (v0.2.0) — controlled-echo dispatchers + edit-UI targets ── */
  const edit = useGanttEdit({
    data,
    editable,
    snap,
    statusOptions,
    onChange,
    onTaskReschedule,
    onItemAdded,
    onItemRemoved,
    onItemMoved,
    onFieldEdited,
    onStatusChanged,
    permissions,
    canMoveItem,
    canResizeItem,
    canDeleteItem,
    canCreateChild,
    canEditItem,
    onPermissionDenied,
  });

  // Stable locals for the clipboard-effect deps (`edit` is a fresh object each
  // render; its state fields + useCallback dispatchers are the real dependencies).
  const {
    editingId: editEditingId,
    renamingId: editRenamingId,
    composerTarget: editComposerTarget,
    deleteItem: editDeleteItem,
    nodeInfo: editNodeInfo,
    pasteTasks: editPasteTasks,
  } = edit;

  /* ── cross-surface clipboard (v0.5.0) — copy/cut/paste TodoItems through the OS
        clipboard (shared ilinxa/task envelope; foreign text ignored). Document-level
        so it fires regardless of the focused element; gated on the gantt containing
        focus, skipped over text inputs + while an editor/rename/composer is up. ── */
  useEffect(() => {
    if (!editable) return;
    const owns = () => {
      const active = document.activeElement;
      return !!rootRef.current && !!active && rootRef.current.contains(active);
    };
    const overText = () => {
      const el = document.activeElement as HTMLElement | null;
      return (
        el?.tagName === "INPUT" ||
        el?.tagName === "TEXTAREA" ||
        el?.isContentEditable === true
      );
    };
    const busy = () =>
      editEditingId != null ||
      editRenamingId != null ||
      editComposerTarget != null;
    const targetId = (): string | null => selectedVal ?? focusedId;
    const onCopy = (e: ClipboardEvent) => {
      if (!owns() || overText() || busy()) return;
      const id = targetId();
      const item = id ? itemIndex.get(id) : undefined;
      if (!item) return;
      writeTasksToClipboardEvent(e, [item], "gantt-timeline-01");
      e.preventDefault();
    };
    const onCut = (e: ClipboardEvent) => {
      if (!owns() || overText() || busy()) return;
      const id = targetId();
      const item = id ? itemIndex.get(id) : undefined;
      if (!item) return;
      writeTasksToClipboardEvent(e, [item], "gantt-timeline-01");
      editDeleteItem(item.id);
      e.preventDefault();
    };
    const onPaste = (e: ClipboardEvent) => {
      if (!owns() || overText() || busy()) return;
      const items = readTasksFromClipboardEvent(e);
      if (!items) return;
      // Paste as a sibling of the target (root if none); dates preserved.
      const id = targetId();
      const info = id ? editNodeInfo(id) : undefined;
      editPasteTasks(
        items,
        info?.parentId ?? null,
        info ? info.index + 1 : undefined,
      );
      e.preventDefault();
    };
    document.addEventListener("copy", onCopy);
    document.addEventListener("cut", onCut);
    document.addEventListener("paste", onPaste);
    return () => {
      document.removeEventListener("copy", onCopy);
      document.removeEventListener("cut", onCut);
      document.removeEventListener("paste", onPaste);
    };
  }, [
    editable,
    editEditingId,
    editRenamingId,
    editComposerTarget,
    editDeleteItem,
    editNodeInfo,
    editPasteTasks,
    selectedVal,
    focusedId,
    itemIndex,
  ]);

  /* ── vertical scroll sync (body drives, gutter mirrors) ── */
  const onBodyScroll = useCallback((scrollTop: number) => {
    if (gutterTrackRef.current) {
      gutterTrackRef.current.style.transform = `translateY(${-scrollTop}px)`;
    }
  }, []);

  /* ── scroll-to-item (expand ancestors, then center) ── */
  const scrollToItemId = useCallback(
    (id: string) => {
      const anc = ancestorsOf(data, id);
      if (anc.length) {
        const next = new Set(collapsedSet);
        anc.forEach((a) => next.delete(a));
        setCollapsed(next);
      }
      const item = itemIndex.get(id);
      if (item) vp.scrollToMs(effStartMs(item));
      requestAnimationFrame(() => {
        const idx = rowsRef.current.findIndex((r) => r.item.id === id);
        const el = bodyScrollRef.current;
        if (idx >= 0 && el) {
          el.scrollTop = Math.max(
            0,
            idx * rowHeight - el.clientHeight / 2 + rowHeight / 2,
          );
        }
      });
    },
    [data, collapsedSet, setCollapsed, itemIndex, vp, rowHeight],
  );

  /* ── imperative handle ── */
  useImperativeHandle(
    ref,
    () => ({
      scrollToDate: (d) => vp.scrollToMs(Date.parse(d)),
      scrollToItem: (id) => scrollToItemId(id),
      scrollToToday: () => vp.scrollToToday(),
      expandAll: () => setCollapsed(new Set()),
      collapseAll: () => setCollapsed(new Set(parentIds(data))),
      setZoom: (z) => vp.setZoomLevel(z),
      zoomBy: (f) => vp.zoomBy(f),
      zoomToFit: () => vp.zoomToFit(),
      addTask: (parentId, item) => edit.createItem(parentId, item),
      deleteTask: (id) => edit.deleteItem(id),
      editTask: (id) => edit.openEditor(id),
      beginRename: (id) => edit.beginRename(id),
      shiftTaskGroup: (id, deltaMs) => edit.moveSubtree(id, deltaMs),
    }),
    [vp, scrollToItemId, setCollapsed, data, edit],
  );

  const ctx: GanttContextValue = {
    rows,
    renderItems,
    totalSize,
    rowHeight,
    gutterWidth,
    bodyScrollRef,
    gutterTrackRef,
    onBodyScroll,
    measureRows: () => {},
    viewport: vp.viewport,
    bodyWidth,
    setBodyWidth,
    dataExtent: extent,
    disableGestures,
    onPan: vp.onPan,
    onZoomAt: vp.onZoomAt,
    beginPan: vp.beginPan,
    endPanWithVelocity: vp.endPanWithVelocity,
    namedZoom: vp.namedZoom,
    setZoomLevel: vp.setZoomLevel,
    zoomBy: vp.zoomBy,
    zoomToFit: vp.zoomToFit,
    scrollToToday: vp.scrollToToday,
    scrollToItemId,
    pageBy: vp.pageBy,
    nowMs,
    showTodayLine,
    resolveColor,
    geometryFor,
    summarySpanFor,
    statusOptions,
    priorityOptions,
    labelOptions,
    showWeekendShading,
    isCollapsed,
    toggleCollapse,
    selectedId: selectedVal,
    select,
    onTaskClick,
    renderTooltip,
    focusedId,
    setFocusedId,

    // editing (v0.2.0)
    editable,
    snap,
    drawMode,
    setDrawMode,
    permissions,
    getItem: (id: string) => itemIndex.get(id),
    can: edit.can,
    canGroupMove: edit.canGroupMove,
    nodeInfo: edit.nodeInfo,
    rescheduleItem: edit.rescheduleItem,
    createItem: edit.createItem,
    deleteItem: edit.deleteItem,
    renameItemAction: edit.renameItemAction,
    moveItemAction: edit.moveItemAction,
    moveSubtree: edit.moveSubtree,
    changeStatus: edit.changeStatus,
    changePriority: edit.changePriority,
    editingId: edit.editingId,
    openEditor: edit.openEditor,
    closeEditor: edit.closeEditor,
    applyEditedSubtree: edit.applyEditedSubtree,
    renamingId: edit.renamingId,
    beginRename: edit.beginRename,
    endRename: edit.endRename,
    // quick-create composer (v0.5.0)
    quickCompose,
    renderQuickComposer,
    composerTarget: edit.composerTarget,
    openComposer: edit.openComposer,
    closeComposer: edit.closeComposer,
    // cross-surface clipboard (v0.5.0)
    copyItem: edit.copyItem,
    cutItem: edit.cutItem,
    pasteTasks: edit.pasteTasks,
  };

  return (
    <GanttContext.Provider value={ctx}>
      <div
        ref={rootRef}
        role="group"
        aria-label={ariaLabel ?? "Gantt timeline"}
        className={cn("text-foreground", className)}
      >
        {children}
      </div>
      {editable ? <GanttEditPopover /> : null}
      {editable ? <GanttQuickComposer /> : null}
    </GanttContext.Provider>
  );
});

"use client";

import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";

/** Tier C — loading placeholder (axis + rows). Zero state; composes anywhere. */
export function GanttTimelineSkeleton({
  rows = 7,
  gutterWidth = 280,
  rowHeight = 36,
  className,
}: {
  rows?: number;
  gutterWidth?: number;
  rowHeight?: number;
  className?: string;
}) {
  return (
    <div
      className={cn(
        "overflow-hidden rounded-lg border border-border bg-card",
        className,
      )}
      aria-busy
      aria-label="Loading timeline"
    >
      <div className="flex border-b border-border">
        <div
          className="flex shrink-0 items-center border-r border-border p-2"
          style={{ width: gutterWidth }}
        >
          <Skeleton className="h-4 w-24" />
        </div>
        <div className="flex grow items-center gap-6 p-2">
          {Array.from({ length: 6 }).map((_, i) => (
            <Skeleton key={i} className="h-4 w-16" />
          ))}
        </div>
      </div>
      {Array.from({ length: rows }).map((_, i) => (
        <div
          key={i}
          className="flex border-b border-border/40"
          style={{ height: rowHeight }}
        >
          <div
            className="flex shrink-0 items-center gap-2 border-r border-border px-2"
            style={{ width: gutterWidth, paddingLeft: 8 + (i % 3) * 16 }}
          >
            <Skeleton className="size-4 rounded-full" />
            <Skeleton className="h-3.5 w-28" />
          </div>
          <div className="flex grow items-center px-3">
            <Skeleton
              className="h-4 rounded"
              style={{
                width: `${28 + ((i * 37) % 48)}%`,
                marginLeft: `${(i * 53) % 30}%`,
              }}
            />
          </div>
        </div>
      ))}
    </div>
  );
}

"use client";

import { CalendarClock, Maximize2, Minus, Pencil, Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttZoom } from "../types";

const ZOOMS: { value: GanttZoom; label: string }[] = [
  { value: "hour", label: "H" },
  { value: "day", label: "D" },
  { value: "week", label: "W" },
  { value: "month", label: "M" },
  { value: "quarter", label: "Q" },
];

export function GanttTimelineToolbar({ className }: { className?: string }) {
  const {
    namedZoom,
    setZoomLevel,
    zoomBy,
    zoomToFit,
    scrollToToday,
    editable,
    drawMode,
    setDrawMode,
  } = useGanttTimeline();
  return (
    <div
      className={cn(
        "flex items-center gap-1.5 border-b border-border bg-card px-2 py-1.5",
        className,
      )}
    >
      <Button
        type="button"
        size="sm"
        variant="ghost"
        className="h-7 gap-1.5 px-2 text-xs"
        onClick={scrollToToday}
      >
        <CalendarClock className="size-3.5" /> Today
      </Button>
      <Separator orientation="vertical" className="mx-0.5 h-5" />
      <Button
        type="button"
        size="icon"
        variant="outline"
        className="size-7"
        aria-label="Zoom out"
        onClick={() => zoomBy(0.7)}
      >
        <Minus className="size-3.5" />
      </Button>
      <Button
        type="button"
        size="icon"
        variant="outline"
        className="size-7"
        aria-label="Zoom in"
        onClick={() => zoomBy(1 / 0.7)}
      >
        <Plus className="size-3.5" />
      </Button>
      <Button
        type="button"
        size="sm"
        variant="ghost"
        className="h-7 gap-1.5 px-2 text-xs"
        onClick={zoomToFit}
      >
        <Maximize2 className="size-3.5" /> Fit
      </Button>
      <Separator orientation="vertical" className="mx-0.5 h-5" />
      <div
        role="group"
        aria-label="Zoom level"
        className="ml-auto inline-flex overflow-hidden rounded-md border border-border"
      >
        {ZOOMS.map((z) => (
          <button
            key={z.value}
            type="button"
            aria-pressed={namedZoom === z.value}
            onClick={() => setZoomLevel(z.value)}
            className={cn(
              "h-7 w-7 text-xs font-medium transition-colors",
              namedZoom === z.value
                ? "bg-primary text-primary-foreground"
                : "bg-card text-muted-foreground hover:bg-muted hover:text-foreground",
            )}
          >
            {z.label}
          </button>
        ))}
      </div>
      {editable ? (
        <>
          <Separator orientation="vertical" className="mx-0.5 h-5" />
          <Button
            type="button"
            size="sm"
            variant={drawMode ? "default" : "ghost"}
            aria-pressed={drawMode}
            title="Draw mode — drag an empty row to create a task (off = drag to pan)"
            className="h-7 gap-1.5 px-2 text-xs"
            onClick={() => setDrawMode(!drawMode)}
          >
            <Pencil className="size-3.5" /> Draw
          </Button>
        </>
      ) : null}
    </div>
  );
}
